import React from 'react';

export default function GeneralNote({
  // 💡 기본 짐 (UI, 네비게이션)
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 상태 및 데이터 짐
  date,
  generalNotes = [],
  setGeneralNotes,
  currentGenNoteId,
  setCurrentGenNoteId,
  bibles = [],
  
  // 💡 캔버스 및 에디터 짐
  genEditorRef,
  renderToolbar,
  CanvasEngine,
  tool, setTool,
  color, setColor,
  size, setSize,
  StickerLayer,
  onPtrDown,
  RichTextEditor,
  
  // 💡 함수 짐
  getArr
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  const isSp = false;

  // 1. 선택된 노트가 없을 때: 일반 자유 노트 목록 화면 렌더링
  if (!currentGenNoteId) {
      return (
          <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
              <SubPageHeader title="일반 자유 노트 목록" onBack={()=>setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
              <div className="p-4 md:p-5 pb-40 flex-1 overflow-y-auto">
                  <button onClick={() => {
                      const newNote = { id: Date.now(), title: '', date: date, content: '', memos: [], stickers: [] };
                      if (setGeneralNotes) setGeneralNotes([newNote, ...getArr(generalNotes)]);
                      if (setCurrentGenNoteId) setCurrentGenNoteId(newNote.id);
                  }} className={`w-full py-3 md:py-4 rounded-xl font-bold text-[15px] md:text-lg shadow-sm transition-colors ${t.primaryBg} text-white hover:opacity-90 mb-5 md:mb-6`}>
                      + 새 노트 작성하기
                  </button>
                  
                  <div className="space-y-3 md:space-y-4">
                      {getArr(generalNotes).length === 0 ? <div className={`text-center py-10 ${t.textSub} text-[13px] md:text-sm`}>작성된 자유 노트가 없습니다.</div> : getArr(generalNotes).map(n => (
                          <div key={n.id} className={`p-4 rounded-2xl border ${t.border} ${t.cardBg} shadow-sm flex flex-col hover:-translate-y-1 transition-transform`}>
                              <div className="flex justify-between items-start mb-2">
                                  <div className="flex-1 cursor-pointer" onClick={() => setCurrentGenNoteId && setCurrentGenNoteId(n.id)}>
                                      <span className={`text-[9px] md:text-[10px] font-bold ${t.textSub} bg-[#E5E5EA] dark:bg-[#2C2C2E] px-2 py-0.5 rounded-md mb-2 inline-block`}>{n.date}</span>
                                      <h3 className={`font-extrabold text-[15px] md:text-base ${t.textMain} truncate`}>{n.title || '제목 없는 노트'}</h3>
                                  </div>
                                  <button onClick={(e) => { e.stopPropagation(); if(window.confirm('노트를 삭제하시겠습니까?')) if(setGeneralNotes) setGeneralNotes(getArr(generalNotes).filter(x => x.id !== n.id)); }} className={`ml-4 text-[9px] md:text-[10px] bg-[#FF2D55]/15 ${t.pinkText} px-2 py-1 rounded shadow-sm whitespace-nowrap`}>삭제</button>
                              </div>
                              <div className={`text-[11px] md:text-xs ${t.textSub} line-clamp-2 mt-1 cursor-pointer`} onClick={() => setCurrentGenNoteId && setCurrentGenNoteId(n.id)} dangerouslySetInnerHTML={{__html: n.content ? n.content.replace(/<[^>]+>/g, '') : '내용이 없습니다.'}}></div>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      );
  }
  
  // 2. 선택된 노트가 있을 때: 자유 노트 편집 화면 렌더링
  const currentNote = getArr(generalNotes).find(n => n.id === currentGenNoteId);
  if (!currentNote) { if(setCurrentGenNoteId) setCurrentGenNoteId(null); return null; }
  
  const updateCurrentNote = (updater) => { 
      if(setGeneralNotes) setGeneralNotes(getArr(generalNotes).map(n => n.id === currentGenNoteId ? {...n, ...updater} : n)); 
  };

  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
      <SubPageHeader title="자유 노트 편집" onBack={()=>setCurrentGenNoteId && setCurrentGenNoteId(null)} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
      
      {renderToolbar && renderToolbar(genEditorRef, true, 
          (src, isEmoji) => updateCurrentNote({ stickers: [...getArr(currentNote.stickers), { id: Date.now(), src, isEmoji, x: 40, y: 150 }] }), 
          (animal) => updateCurrentNote({ memos: [...getArr(currentNote.memos), { id: Date.now(), animal, text: '', x: 40, y: 150 }] }), 
          (e) => { const file = e.target.files[0]; if (file) { const reader = new FileReader(); reader.onload = (ev) => updateCurrentNote({ stickers: [...getArr(currentNote.stickers), { id: Date.now(), src: ev.target.result, isEmoji: false, x: 40, y: 150 }] }); reader.readAsDataURL(file); } }
      )}
      
      {CanvasEngine && (
      <CanvasEngine key={`generalNote_${currentNote.id}`} saveKey={`generalNote_${currentNote.id}`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={currentNote.memos} stickers={currentNote.stickers} onUpdateMemos={(m)=>updateCurrentNote({memos:m})} onUpdateStickers={(s)=>updateCurrentNote({stickers:s})} onPtrDown={onPtrDown} /> : null}>
        <div className="p-4 sm:p-6 flex flex-col pb-40 min-h-[90vh]">
          <div className={`flex-1 flex flex-col rounded-2xl overflow-hidden min-h-[600px] border ${t.border} shadow-sm ${t.cardBg}`}>
               <div className={`p-3 md:p-4 border-b ${t.border} ${t.appBg} flex flex-col sm:flex-row gap-2 md:gap-3 items-start sm:items-center z-10 relative pointer-events-auto`}>
                  <div className="flex items-center gap-2">
                      <span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase shrink-0 whitespace-nowrap bg-[#E5E5EA] dark:bg-[#2C2C2E] px-2 py-1 rounded border ${t.border}`}>작성일</span>
                      <input type="date" value={currentNote.date||date} onChange={e=>updateCurrentNote({date:e.target.value})} onPointerDown={e => e.stopPropagation()} className={`h-8 md:h-10 px-2 md:px-3 rounded-lg text-[11px] md:text-xs font-bold border outline-none ${t.inputBg} ${t.textMain}`} />
                  </div>
                  <div className="flex-1 w-full flex items-center gap-2">
                      <span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase shrink-0 whitespace-nowrap bg-[#E5E5EA] dark:bg-[#2C2C2E] px-2 py-1 rounded border ${t.border}`}>제목</span>
                      <input type="text" value={currentNote.title||''} onChange={e=>updateCurrentNote({title:e.target.value})} onPointerDown={e => e.stopPropagation()} className={`flex-1 h-8 md:h-10 px-3 md:px-4 rounded-lg text-[13px] md:text-sm font-bold border outline-none ${t.inputBg} ${t.textMain}`} placeholder="노트 제목을 입력하세요..." />
                  </div>
               </div>
               <div className={`flex-1 ${t.cardBg} relative z-0`}>
                 {RichTextEditor && <RichTextEditor ref={genEditorRef} value={currentNote.content} onChange={(val) => updateCurrentNote({content: val})} t={t} isSp={isSp} bibles={bibles} placeholder="말씀(예: 창세기 1:1 후 스페이스바)을 가져오고 자유롭게 필기하세요..." />}
               </div>
          </div>
        </div>
      </CanvasEngine>
      )}
    </div>
  );
}