import React from 'react';

export default function Diary({
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 붙여넣은 UI를 보고 새로 추가한 짐들입니다!
  openModal,
  currDay,
  bibleNotes,
  getArr,
  HeartIcon,
  BibleIcon,
  DiaryIcon
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;
  if (!HeartIcon) return <div className="p-10 font-bold text-red-500">❌ App.js에서 HeartIcon이 넘어오지 않았습니다!</div>;
  if (!BibleIcon) return <div className="p-10 font-bold text-red-500">❌ App.js에서 BibleIcon이 넘어오지 않았습니다!</div>;
  if (!DiaryIcon) return <div className="p-10 font-bold text-red-500">❌ App.js에서 DiaryIcon이 넘어오지 않았습니다!</div>;

  // 1. 계산 로직 (안전장치 추가)
  // 데이터가 아직 안 들어왔을 때 에러가 나지 않도록 기본값을 세팅해 줍니다.
  const safeDay = currDay || {};
  const safeNotes = getArr ? getArr(bibleNotes) : (bibleNotes || []);

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up relative`}>
       <SubPageHeader title="감사/간증 일기" onBack={() => setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
       <div className="flex-1 overflow-y-auto p-4 sm:p-5 pb-32 space-y-4">
          
          <div onClick={() => openModal('thanks')} className={`${t.cardBg} p-5 rounded-[24px] cursor-pointer shadow-sm border ${t.border} hover:shadow-md transition-shadow`}>
              <h3 className={`font-bold text-[14px] flex items-center gap-2 ${t.textMain} mb-3 border-b ${t.border} pb-3`}><HeartIcon className={`w-5 h-5 ${t.pinkText}`} isDark={isDarkMode}/> 오늘의 감사 리스트</h3>
              <div className={`text-[13px] ${t.textSub} leading-relaxed line-clamp-3`}>{safeDay.thanksText || "오늘의 감사를 기록하세요."}</div>
          </div>
          
          <div className={`${t.cardBg} p-5 rounded-[24px] border ${t.border} shadow-sm`}>
              <h3 className={`font-bold text-[14px] flex items-center gap-2 ${t.textMain} mb-3 border-b ${t.border} pb-3`}><BibleIcon className={`w-5 h-5 ${t.primaryText}`} isDark={isDarkMode}/> 말씀 묵상 노트</h3>
              <div className="flex flex-col gap-3">
                  {safeNotes.length === 0 ? <div className={`text-[13px] ${t.textSub}`}>작성된 말씀 묵상이 없습니다.</div> : safeNotes.map(n => (
                      <div key={n.id} onClick={() => openModal('bibleNoteList', n)} className="flex items-start gap-2 cursor-pointer hover:opacity-70 group">
                          <span className="text-[13px] mt-0.5">📖</span>
                          <p className={`text-[13px] ${t.textSub} truncate flex-1 group-hover:${t.primaryText} transition-colors`}>{n.note || "내용 없음"}</p>
                      </div>
                  ))}
              </div>
          </div>
          
          <div onClick={() => openModal('testimony')} className={`${t.cardBg} p-5 rounded-[24px] border ${t.border} cursor-pointer shadow-sm hover:shadow-md transition-shadow`}>
              <h3 className={`font-bold text-[14px] flex items-center gap-2 ${t.textMain} mb-3 border-b ${t.border} pb-3`}><DiaryIcon className={`w-5 h-5 ${t.purpleText}`} isDark={isDarkMode}/> 나의 묵상 간증</h3>
              <div className={`text-[13px] ${t.textSub} leading-relaxed line-clamp-3 font-yeongnamnu`}>{safeDay.testimony && safeDay.testimony.length > 50 ? safeDay.testimony : <span className="font-sans">오늘의 묵상과 간증을 기록하세요.</span>}</div>
          </div>
          
       </div>
    </div>
  );
}