import React from 'react';

export default function Interlinear({
  // 💡 상태 및 네비게이션
  t,
  setActiveScreen,
  setIsSidebarOpen,
  
  // 💡 원어 성경 관련 상태 및 데이터
  interWords,
  interBook,
  setInterBook,
  interChapter,
  setInterChapter,
  interVerse,
  setInterVerse,
  bibles,
  isLoadingInter,
  
  // 💡 유틸리티 함수 및 모달
  getArr,
  getKoName,
  openModal
}) {
  // 1. 계산 로직 (기존 switch문 상단에 있던 로직)
  const isHebrew = getArr(interWords).length > 0 && (interWords[0]?.strongs_id || interWords[0]?.strongs)?.startsWith('H');
  const currentBibleObj = getArr(bibles).find(b => b.name === interBook);
  const koreanVerseText = currentBibleObj?.chapters?.[interChapter - 1]?.[interVerse - 1] || '해당 구절을 불러오는 중입니다.';
  const englishVerseText = getArr(interWords).map(w => w.eng || w.gloss).filter(Boolean).join(' ');

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full bg-[#F8F9FA] dark:bg-[#121212] animate-fade-in-up`}>
      {/* 상단 네비게이션 */}
      <div className="bg-white dark:bg-[#1C1C1E] px-4 py-3 flex items-center justify-between border-b border-[#E5E5EA] dark:border-[#2C2C2E] shrink-0 pointer-events-auto z-[60]">
        <div className="flex items-center gap-3">
            <button onClick={() => setIsSidebarOpen(true)} className={`${t.textMain} text-xl p-1`}>☰</button>
            <button onClick={() => setActiveScreen('home')} className={`${t.textMain} text-xl font-bold p-1`}>&larr;</button>
            <h1 className={`text-lg font-bold ${t.textMain}`}>원어 성경 연구 (BETA)</h1>
        </div>
      </div>
      
      <div className="flex-1 overflow-y-auto pb-40 z-20 pointer-events-auto">
        {/* 성경 본문 뷰어 카드 */}
        <div className={`bg-white dark:bg-[#1C1C1E] m-4 md:m-5 p-5 md:p-6 rounded-2xl shadow-[0_4px_20px_rgba(0,0,0,0.03)] border border-[#E5E5EA] dark:border-[#2C2C2E]`}>
            <div className="flex flex-col gap-4">
              {/* 컨트롤러 */}
              <div className="flex flex-wrap items-center gap-2 border-b border-[#E5E5EA] dark:border-[#3A3A3C] pb-4 mb-2">
                  <select value={interBook} onChange={(e) => { setInterBook(e.target.value); setInterChapter(1); setInterVerse(1); }} className={`h-10 px-3 text-[14px] font-bold rounded-lg border border-[#E5E5EA] dark:border-[#3A3A3C] outline-none bg-[#F5F6F8] dark:bg-[#2C2C2E] text-[#3B48E0] dark:text-[#5E6AD2]`}>
                    {getArr(bibles).map(b => <option key={b.name} value={b.name}>{getKoName(b.name)}</option>)}
                  </select>
                  <div className="flex items-center bg-[#F5F6F8] dark:bg-[#2C2C2E] rounded-lg border border-[#E5E5EA] dark:border-[#3A3A3C] h-10 px-1">
                    <input type="number" min="1" value={interChapter} onChange={(e) => setInterChapter(Math.max(1, parseInt(e.target.value) || 1))} className="w-10 h-full text-center text-[14px] font-bold bg-transparent outline-none" />
                    <span className="text-[13px] font-bold text-[#8E8E93]">장</span>
                    <span className="mx-1 text-[#E5E5EA] dark:text-[#3A3A3C]">|</span>
                    <input type="number" min="1" value={interVerse} onChange={(e) => setInterVerse(Math.max(1, parseInt(e.target.value) || 1))} className="w-10 h-full text-center text-[14px] font-bold bg-transparent outline-none" />
                    <span className="text-[13px] font-bold text-[#8E8E93] mr-2">절</span>
                  </div>
                  <div className="flex gap-1 ml-auto">
                    <button onClick={() => setInterVerse(v => Math.max(1, v - 1))} className={`px-3 h-10 rounded-lg text-sm font-bold border border-[#E5E5EA] dark:border-[#3A3A3C] bg-white dark:bg-[#2C2C2E] ${t.textMain}`}>&lt;</button>
                    <button onClick={() => setInterVerse(v => v + 1)} className={`px-3 h-10 rounded-lg text-sm font-bold border border-[#E5E5EA] dark:border-[#3A3A3C] bg-white dark:bg-[#2C2C2E] ${t.textMain}`}>&gt;</button>
                  </div>
              </div>

              <h3 className={`font-extrabold text-[16px] text-[#3B48E0] dark:text-[#5E6AD2]`}>{getKoName(interBook)} {interChapter}장 {interVerse}절</h3>
              <p className={`text-[17px] font-black ${t.textMain} leading-relaxed`}>{koreanVerseText}</p>
              <p className={`text-[15px] text-[#8E8E93] leading-relaxed -mt-1 font-medium`}>{englishVerseText}</p>
              <p className={`text-[28px] md:text-[34px] font-black ${t.textMain} leading-[1.6] mt-4`} dir={isHebrew ? "rtl" : "ltr"}>
                  {getArr(interWords).map(w => w.hebrew || w.orig || w.original_word).join(' ')}
              </p>
            </div>
        </div>

        {/* 개별 단어 카드 그리드 */}
        {isLoadingInter ? (
            <div className="text-center py-20 text-[#8E8E93] font-bold">데이터를 파싱 중입니다...</div>
        ) : getArr(interWords).length === 0 ? (
            <div className="text-center py-20 text-[#8E8E93]">선택하신 구절의 원어 데이터가 없습니다.</div>
        ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 px-4 md:px-5">
              {getArr(interWords).map((word) => (
                  <div key={word.id} onClick={() => openModal('strongsDic', word)} className={`bg-white dark:bg-[#1C1C1E] p-5 rounded-2xl shadow-sm border border-[#E5E5EA] dark:border-[#2C2C2E] cursor-pointer hover:border-[#3B48E0] transition-colors flex flex-col`}>
                    <span className={`text-[32px] font-black ${t.textMain} mb-2`} dir={isHebrew ? "rtl" : "ltr"}>{word.hebrew || word.orig || word.original_word}</span>
                    <div className="border-b border-[#E5E5EA] dark:border-[#3A3A3C] w-full mb-3"></div>
                    <span className={`text-[12px] text-[#8E8E93] font-mono mb-3`}>[{word.pron}]</span>
                    <span className={`text-[15px] font-extrabold ${t.textMain} mb-1 break-keep`}>{word.kor}</span>
                    <span className={`text-[13px] text-[#8E8E93] mb-3`}>{word.eng || word.gloss}</span>
                    {word.grammar && <div className="mt-auto"><span className="text-[10px] font-bold bg-[#EEF2FF] dark:bg-[#2A2B4A] text-[#3B48E0] dark:text-[#818CF8] px-2 py-1 rounded">{word.grammar}</span></div>}
                  </div>
              ))}
            </div>
        )}
      </div>
    </div>
  );
}