import React from 'react';

export default function PrayerBox({
  // 💡 기본 짐 (UI, 네비게이션)
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 상태 및 데이터 짐
  globalPrayers = [],
  globalIntercessions = [],
  
  // 💡 함수 짐
  openModal,
  getArr,
  
  // 💡 아이콘 짐
  FireIcon,
  PrayingHandsIcon
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  // 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
       <SubPageHeader title="나의 기도 보관함" onBack={() => setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
       <div className="flex-1 overflow-y-auto p-5 pb-40 space-y-4">
          <div className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm cursor-pointer hover:-translate-y-1 transition-transform`} onClick={() => openModal && openModal('globalPrayer')}>
              <h3 className={`font-extrabold text-sm mb-3 border-b pb-2 ${t.border} ${t.textMain} flex items-center gap-1.5`}>{FireIcon && <FireIcon className={`w-5 h-5 ${t.primaryText}`} isDark={isDarkMode}/>} 나의 누적 기도 보드</h3>
              {getArr(globalPrayers).length > 0 ? getArr(globalPrayers).slice(0,3).map(p => <div key={p.id} className={`text-sm ${t.textMain} pl-1 mt-1.5 truncate`}>🔥 {p.text}</div>) : <div className={`text-xs ${t.textSub} mt-2 text-center`}>개인 기도제목을 기록하세요.</div>}
          </div>
          <div className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm cursor-pointer hover:-translate-y-1 transition-transform`} onClick={() => openModal && openModal('globalIntercession')}>
              <h3 className={`font-extrabold text-sm mb-3 border-b pb-2 ${t.border} ${t.textMain} flex items-center gap-1.5`}>{PrayingHandsIcon && <PrayingHandsIcon className={`w-5 h-5 ${t.greenText}`} isDark={isDarkMode}/>} 중보 기도 보드</h3>
              {getArr(globalIntercessions).length > 0 ? getArr(globalIntercessions).slice(0,3).map(p => <div key={p.id} className={`text-sm ${t.textMain} pl-1 mt-1.5 truncate`}>🌱 {p.text}</div>) : <div className={`text-xs ${t.textSub} mt-2 text-center`}>교회와 이웃을 위한 중보기도.</div>}
          </div>
       </div>
    </div>
  );
}