import React from 'react';
import RichTextEditor from '../components/RichTextEditor';

export default function Bible({
  // 기존에 있던 것들
  bibles, currentChapId, setCurrentChapId, bibleViewMode, setBibleViewMode,
  bibleNotes, setBibleNotes, bibleHighlights, setBibleHighlights,
  readVerses, setReadVerses, isDarkMode, t, setActiveScreen,
  isSidebarOpen, setIsSidebarOpen, getKoName,

  // 새롭게 추가로 받아와야 하는 필수 변수/함수들
  getArr, readChallengeStart, setReadChallengeStart, 
  bibleProgress, readChapsCount, openModal, 
  setSelVerses, selVerses, renderToolbar, bibleEditorRef, 
  handleStickerAdd, handleMemoAdd, handleFileUpload,
  CanvasEngine, tool, setTool, color, setColor, size, setSize, 
  StickerLayer, currDay, updateDay, onPtrDown, cleanText, getLocalToday,
  SubPageHeader,
  
  // 🚨 새롭게 추가된 필수 함수!
  handleAutoResize
}) {
  
  // 1. 계산 로직
  const [sBk, sCh] = String(currentChapId || "Genesis-1").split('-'); 
  const cBk = getArr(bibles).find(b => b.name === sBk) || bibles[0]; 
  const cVs = (cBk && cBk.chapters && Array.isArray(cBk.chapters[parseInt(sCh)-1])) ? cBk.chapters[parseInt(sCh)-1] : []; 
  const isAllR = cVs.length > 0 && getArr(cVs).every((_, i) => (readVerses||{})[`${sBk}-${sCh}-${i}`]);

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
       {bibleViewMode === 'index' ? (
          <div className="flex-1 overflow-y-auto p-4 md:p-5 pb-40 space-y-5 md:space-y-6">
             <div className="ignore-draw"><SubPageHeader title="성경 전체 66권" onBack={() => setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} /></div>
             <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} text-center shadow-sm ignore-draw relative z-[45] pointer-events-auto`}>
                <span className={`text-[11px] md:text-xs font-bold ${t.primaryText} block mb-2`}>🗓️ 말씀과 함께하는 365일 기간 설정</span>
                <div className="flex items-center justify-center gap-2 mb-3"><input type="date" value={readChallengeStart} onChange={(e)=>setReadChallengeStart(e.target.value)} className={`${t.inputBg} border ${t.border} text-[11px] md:text-xs font-bold px-3 py-1.5 rounded-lg outline-none date-hidden`} /></div>
                <div className={`w-full ${t.appBg} rounded-full h-2.5 md:h-3.5 overflow-hidden shadow-inner mb-2 border ${t.border}`}><div className={`bg-[#8AB4F8] h-full transition-all duration-500`} style={{width:`${bibleProgress}%`}}></div></div>
                <div className={`flex justify-between text-[10px] md:text-xs font-bold ${t.textMain} px-1`}><span>완독: {readChapsCount}장</span><span className={t.primaryText}>진행도 {bibleProgress}%</span></div>
                <button onClick={() => { openModal('bibleChallenge'); }} className={`w-full mt-3 py-2.5 md:py-3 bg-gradient-to-r from-[#9CB4D8] to-[#8FAADC] text-white dark:text-[#1D1D1F] text-[12px] md:text-sm font-bold rounded-xl shadow-sm hover:opacity-90 transition-opacity`}>📖 365 통독표 상세보기</button>
             </div>
             <div className="mt-4 relative z-[45] pointer-events-auto"><h3 className={`font-extrabold ${t.textMain} text-[15px] md:text-lg mb-2 border-b ${t.border} pb-2 ignore-draw`}>구약 성경</h3><div className="flex flex-wrap gap-1.5 md:gap-2">{getArr(bibles).slice(0, 39).map(b => <button key={b.name} onClick={()=>{openModal('bibleChapterSelect', b);}} className={`px-3 md:px-4 py-1.5 md:py-2 rounded-xl text-[11px] md:text-sm font-bold border ${t.cardBg} ${t.textMain} ${t.border} shadow-sm hover:-translate-y-0.5 transition-transform ignore-draw whitespace-nowrap`}>{getKoName(b.name)}</button>)}</div></div>
             <div className="mt-6 relative z-[45] pointer-events-auto"><h3 className={`font-extrabold ${t.textMain} text-[15px] md:text-lg mb-2 border-b ${t.border} pb-2 ignore-draw`}>신약 성경</h3><div className="flex flex-wrap gap-1.5 md:gap-2">{getArr(bibles).slice(39, 66).map(b => <button key={b.name} onClick={()=>{openModal('bibleChapterSelect', b);}} className={`px-3 md:px-4 py-1.5 md:py-2 rounded-xl text-[11px] md:text-sm font-bold border ${t.cardBg} ${t.textMain} ${t.border} shadow-sm hover:-translate-y-0.5 transition-transform ignore-draw whitespace-nowrap`}>{getKoName(b.name)}</button>)}</div></div>
          </div>
       ) : (
          <div className="flex-1 flex flex-col h-full">
             <div className="ignore-draw"><SubPageHeader title="성경 본문" onBack={()=>{setBibleViewMode('index'); setSelVerses([]);}} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} /></div>
             <div className={`${t.cardBg} px-4 md:px-5 pt-3 pb-3 md:pb-4 shadow-[0_2px_10px_rgba(0,0,0,0.02)] z-[60] border-b ${t.border} flex flex-col gap-3 ignore-draw relative pointer-events-auto`}><div className="flex justify-between items-center"><span className={`font-bold text-[13px] md:text-base ${t.textMain}`}>{getKoName(sBk)} {sCh}장</span><button onClick={()=>{setBibleViewMode('index'); setSelVerses([]);}} className={`h-7 md:h-8 px-2.5 md:px-3 rounded text-[10px] md:text-xs font-bold ${t.appBg} ${t.textMain} border ${t.border}`}>☰ 목록</button></div></div>
             
             {renderToolbar(bibleEditorRef, false, handleStickerAdd, handleMemoAdd, handleFileUpload)}

             <CanvasEngine key={`bible_read_${currentChapId}`} saveKey={`bible_read_${currentChapId}`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => <StickerLayer memos={currDay.memos} stickers={currDay.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} />}>
                 <div className="p-4 sm:p-6 flex flex-col sm:flex-row gap-5 md:gap-8 pb-40 items-stretch flex-1 relative z-10">
                     <div className="flex-1 break-words relative z-[45] pointer-events-auto">
                         <div className={`${t.cardBg} rounded-2xl p-4 md:p-5 shadow-sm border ${t.border}`}>
                         {cVs.length > 0 ? getArr(cVs).map((verse, idx) => { 
                            const vId=`${sBk}-${sCh}-${idx}`; const isR=(readVerses||{})[vId]; const isSel = selVerses.includes(vId); const hColor = (bibleHighlights||{})[vId];
                            return (
                              <p key={idx} onClick={() => { if(tool==='hand') { setReadVerses(p=>({...p, [vId]:!p[vId]})); setSelVerses(p => p.includes(vId) ? p.filter(id=>id!==vId) : [...p, vId]); } }} className={`flex gap-2 md:gap-3 p-2 md:p-3 rounded-xl mb-1 cursor-pointer text-[13px] md:text-sm sm:text-base transition-all ${isSel ? `bg-[#8AB4F8]/20 border-2 border-dashed border-[#8AB4F8]/50 scale-[0.99] ${t.textMain}` : isR && (!hColor || hColor === 'transparent') ? `opacity-40 grayscale text-[#8E8E93]` : `hover:${t.highlight} ${t.textMain}`}`}>
                                 <span className={`font-bold min-w-[1.2rem] md:min-w-[1.5rem] text-right mt-0.5 ${isSel || (hColor && hColor !== 'transparent') ? t.primaryText : isR ? 'text-[#8E8E93]' : t.primaryText}`}>{idx + 1}</span>
                                 <span style={hColor && hColor !== 'transparent' ? {backgroundColor: hColor, padding: '2px 4px', borderRadius: '4px', color: '#1D1D1F'} : {}} className={hColor && hColor !== 'transparent' ? "font-bold shadow-sm" : ""}>{cleanText(verse)}</span>
                              </p>
                            );
                         }) : <p className={`text-center ${t.textSub} mt-4 text-[12px] md:text-sm`}>데이터 없음</p>}
                         </div>
                         <div className="flex justify-between mt-6 gap-2 ignore-draw relative z-[45] pointer-events-auto">
                             <button onClick={()=>{if(parseInt(sCh)>1)setCurrentChapId(`${sBk}-${parseInt(sCh)-1}`)}} className={`w-12 h-12 md:w-14 md:h-14 ${t.appBg} border ${t.border} rounded-full font-black text-lg md:text-xl shadow-sm ${t.textMain}`}>{"<"}</button>
                             <button onClick={()=>{const u={}; const s=!isAllR; getArr(cVs).forEach((_, i)=>u[`${sBk}-${sCh}-${i}`]=s); setReadVerses(p=>({...p, ...u})); if(s) updateDay({ checks: { ...(currDay.checks||{}), '성경읽기': true } }); }} className={`flex-1 h-12 md:h-14 rounded-2xl font-bold text-[12px] md:text-sm ${isAllR ? `${t.appBg} ${t.textSub} border ${t.border}` : `${t.primaryBg} text-white dark:text-[#1D1D1F] shadow-sm`}`}>장 모두 읽음 표시</button>
                             <button onClick={()=>{if(parseInt(sCh)<getArr(cBk.chapters).length)setCurrentChapId(`${sBk}-${parseInt(sCh)+1}`)}} className={`w-12 h-12 md:w-14 md:h-14 ${t.appBg} border ${t.border} rounded-full font-black text-lg md:text-xl shadow-sm ${t.textMain}`}>{">"}</button>
                         </div>
                     </div>
                     <div className={`hidden sm:flex flex-1 flex-col ${t.cardBg} border ${t.border} shadow-sm rounded-2xl overflow-hidden min-h-[500px] relative z-[45] pointer-events-auto`}>
                        <div className={`p-3 border-b ${t.border} ${t.appBg} flex justify-between items-center z-10 ignore-draw`}>
                            <span className={`text-[10px] md:text-xs font-bold ml-2 ${t.textSub}`}>📝 자유 묵상 노트 (성경 구절 타이핑 가능)</span>
                        </div>
                        <RichTextEditor 
                            ref={bibleEditorRef} 
                            value={currDay.bibleFreeNote || ''} 
                            onChange={val => updateDay({ bibleFreeNote: val })} 
                            t={t} 
                            bibles={bibles} 
                            placeholder="구절(예: 요한복음 3:16)을 입력하고 스페이스바를 누르면 본문이 삽입됩니다..." 
                        />
                     </div>
                 </div>
             </CanvasEngine>
          </div>
       )}

       {selVerses.length > 0 && bibleViewMode === 'read' && (
          <div className={`absolute bottom-28 left-1/2 -translate-x-1/2 ${t.cardBg} backdrop-blur-xl shadow-2xl rounded-full px-4 md:px-5 py-2 md:py-3 flex items-center gap-2 md:gap-3 z-50 border ${t.border} animate-fade-in-up ignore-draw pointer-events-auto`}>
             {['transparent', '#fef08a', '#bfdbfe', '#fecaca', '#e9d5ff', '#bbf7d0'].map(c => ( <button key={c} onClick={() => { const nH = {...bibleHighlights}; const nR = {...readVerses}; selVerses.forEach(id => { nH[id] = c; if(c!=='transparent') nR[id]=true; }); setBibleHighlights(nH); setReadVerses(nR); setSelVerses([]); }} className={`w-6 h-6 md:w-8 md:h-8 rounded-full shadow-inner border hover:scale-110 transition-transform flex items-center justify-center text-[10px] md:text-xs ${c === 'transparent' ? 'border-[#FF2D55]' : 'border-[#E5E5EA]'}`} style={{backgroundColor: c !== 'transparent' ? c : (isDarkMode ? '#1C1C1E' : '#ffffff')}}>{c === 'transparent' ? '❌' : ''}</button> ))}
             <div className={`w-px h-5 md:h-6 ${t.border} mx-0.5 md:mx-1`}></div>
             <button onClick={() => { 
               const vData = selVerses.map(id => { 
                 const [b, ch, vIdx] = id.split('-'); 
                 const bD = getArr(bibles).find(x => x.name === b) || bibles[0]; 
                 const verseText = getArr(getArr(bD?.chapters)[parseInt(ch)-1])[parseInt(vIdx)] || ''; 
                 return { id, ref: `${getKoName(b)} ${ch}:${parseInt(vIdx)+1}`, text: cleanText(verseText) }; 
               }); 
               openModal('bibleNoteCreate', { verses: vData, note: '' }, (d) => { setBibleNotes(p => [{ id: Date.now(), date: getLocalToday(), ...d }, ...getArr(p)]); setSelVerses([]); }); 
             }} className={`bg-[#1D1D1F] dark:bg-white text-white dark:text-[#1D1D1F] text-[10px] md:text-xs font-bold px-3 md:px-4 py-2 md:py-2.5 rounded-full shadow-sm hover:opacity-90 whitespace-nowrap`}>📝 노트하기</button>
          </div>
       )}
    </div>
  );
}