import React from 'react';

// ✅ 하위 컴포넌트나 아이콘들은 실제 프로젝트 경로에 맞게 임포트가 필요할 수 있습니다.
// import SubPageHeader from '../components/SubPageHeader'; 
// import { SearchIcon, MapIcon, BibleIcon } from '../components/Icons'; 

export default function BibleWiki({
  wikiSearchTerm,
  setWikiSearchTerm,
  bibles,
  getKoName,
  setActiveScreen,
  isDarkMode,
  t,
  isSidebarOpen,
  setIsSidebarOpen,
  setCurrentChapId,
  setBibleViewMode
}) {
  
  // 1. 위키 검색 결과 계산 로직
  const getWikiResults = () => {
    if (!wikiSearchTerm || wikiSearchTerm.trim().length < 2) return { list: [], total: 0 };
    
    const results = [];
    const search = wikiSearchTerm.trim();
    let totalCount = 0;
    
    if (!bibles || !Array.isArray(bibles)) return { list: [], total: 0 };
    
    for (let b of bibles) {
        if (!b.chapters) continue;
        for (let cIdx = 0; cIdx < b.chapters.length; cIdx++) {
            const verses = b.chapters[cIdx];
            if (!verses) continue;
            for (let vIdx = 0; vIdx < verses.length; vIdx++) {
                if (verses[vIdx] && verses[vIdx].includes(search)) {
                    totalCount++;
                    if (results.length < 200) {
                        const rawText = typeof verses[vIdx] === 'string' ? verses[vIdx].replace(/<[^>]+>/g, '') : '';
                        results.push({ 
                            book: getKoName ? getKoName(b.name) : b.name, 
                            rawBook: b.name,
                            chapter: cIdx + 1, 
                            verse: vIdx + 1, 
                            text: rawText 
                        });
                    }
                }
            }
        }
    }
    return { list: results, total: totalCount };
  };

  const foundVerses = getWikiResults();

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full bg-[#F5F6F8] dark:bg-[#121212] animate-fade-in-up`}>
       {/* 🚨 SubPageHeader 컴포넌트가 다른 파일에 있다면 App.js 상단에서 복사해와야 합니다 */}
       <div className={`flex items-center h-14 px-4 border-b border-[#E5E5EA] dark:border-[#2C2C2E] shrink-0 bg-white dark:bg-[#1C1C1E]`}>
          <button onClick={() => setActiveScreen('home')} className="p-2 -ml-2 text-[#8E8E93]">
             {/* 뒤로가기 아이콘 임시 처리 */}
             <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M15 18l-6-6 6-6"/></svg>
          </button>
          <h1 className={`flex-1 text-center font-bold ${t.textMain}`}>성경 위키 (마인드맵 구조화)</h1>
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 -mr-2 text-[#8E8E93]">
             <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 6h16M4 12h16M4 18h16"/></svg>
          </button>
       </div>
       
       {/* 검색 및 필터 파트 */}
       <div className={`bg-white dark:bg-[#1C1C1E] px-4 py-4 border-b border-[#E5E5EA] dark:border-[#2C2C2E] flex flex-col gap-3 shrink-0 z-30 pointer-events-auto shadow-sm`}>
          <div className="relative">
             <input 
               type="text" 
               placeholder="인물, 사건, 장소를 검색하세요 (최소 2글자)" 
               value={wikiSearchTerm}
               onChange={(e) => setWikiSearchTerm(e.target.value)}
               className={`w-full h-12 px-4 rounded-xl text-[14px] font-bold border border-[#E5E5EA] dark:border-[#3A3A3C] outline-none bg-[#F5F6F8] dark:bg-[#2C2C2E] ${t.textMain} focus:border-[#3B48E0] transition-colors`} 
             />
          </div>
          <div className="flex gap-2 overflow-x-auto hide-scrollbar pb-1">
              {['아브라함', '야곱', '모세', '다윗', '예루살렘', '갈릴리', '바울', '성전'].map((tag) => (
                  <button key={tag} onClick={() => setWikiSearchTerm(tag)} className={`px-4 h-8 rounded-full text-[12px] font-bold whitespace-nowrap transition-colors ${wikiSearchTerm === tag ? 'bg-[#3B48E0] text-white shadow-sm' : `bg-[#F5F6F8] dark:bg-[#2C2C2E] ${t.textSub} border border-transparent hover:border-[#E5E5EA] dark:hover:border-[#3A3A3C]`}`}>#{tag}</button>
              ))}
          </div>
       </div>

       {/* 결과 파트 */}
       <div className="flex-1 overflow-y-auto p-4 md:p-6 pb-40 z-20 pointer-events-auto relative">
          {!wikiSearchTerm ? (
              <div className="h-full flex flex-col items-center justify-center text-center opacity-50 pt-20">
                 <h3 className={`text-lg font-bold ${t.textMain}`}>성경 66권 통합 위키 검색</h3>
                 <p className={`text-sm ${t.textSub} mt-2 max-w-[250px]`}>단어나 인물을 검색하시면, 관련된 모든 성경 구절이 마인드맵 구조로 연결됩니다.</p>
              </div>
          ) : wikiSearchTerm.length < 2 ? (
              <div className="text-center py-10 text-[#8E8E93] font-bold">정확한 검색을 위해 2글자 이상 입력해 주세요.</div>
          ) : foundVerses.total === 0 ? (
              <div className="text-center py-10 text-[#8E8E93] font-bold">검색 결과가 없습니다.</div>
          ) : (
              <div className="relative">
                  {/* 마인드맵 중심 노드 */}
                  <div className="flex justify-center mb-10 relative z-20">
                      <div className="bg-[#3B48E0] text-white px-8 py-4 rounded-2xl shadow-xl border-4 border-[#EEF2FF] dark:border-[#2A2B4A] text-center">
                          <span className="block text-[11px] font-bold text-blue-200 mb-1">검색된 핵심 키워드</span>
                          <h2 className="text-2xl font-black">{wikiSearchTerm}</h2>
                          <span className="block mt-2 text-xs font-bold bg-white/20 px-2 py-1 rounded-full">총 {foundVerses.total}개의 연결 구절 발견</span>
                      </div>
                  </div>
                  {/* 세로 트리 라인 */}
                  <div className="absolute left-[24px] md:left-[36px] top-[100px] bottom-10 w-1 bg-[#3B48E0]/20 z-0 rounded-full"></div>

                  <div className="flex flex-col gap-6 relative z-10 pl-2">
                      {foundVerses.list.map((v, i) => {
                          const highlightedText = v.text.split(new RegExp(`(${wikiSearchTerm})`, 'gi'));
                          return (
                          <div key={i} className="relative flex items-center gap-4 group">
                              <div className="w-3 h-3 rounded-full bg-[#3B48E0] shrink-0 z-10 ml-[9px] md:ml-[21px] ring-4 ring-white dark:ring-[#121212] group-hover:scale-150 transition-transform"></div>
                              <div onClick={() => { setActiveScreen('bible'); setCurrentChapId(`${v.rawBook}-${v.chapter}`); setBibleViewMode('read'); }} className={`flex-1 p-4 md:p-5 rounded-[20px] bg-white dark:bg-[#1C1C1E] border border-[#E5E5EA] dark:border-[#2C2C2E] shadow-[0_2px_10px_rgba(0,0,0,0.03)] cursor-pointer hover:border-[#3B48E0] transition-colors flex flex-col gap-2`}>
                                  <div className="flex justify-between items-center">
                                     <span className={`text-xs font-black text-white bg-[#3B48E0] px-2.5 py-1 rounded-md shadow-sm`}>{v.book} {v.chapter}:{v.verse}</span>
                                     <span className={`text-[10px] text-[#8E8E93] font-bold`}>전체 장 펼쳐보기</span>
                                  </div>
                                  <p className={`text-[14px] md:text-[15px] ${t.textMain} leading-relaxed break-keep font-yeongnamnu mt-1`}>
                                     {highlightedText.map((part, index) => 
                                        part.toLowerCase() === wikiSearchTerm.toLowerCase() 
                                          ? <span key={index} className="bg-yellow-200 dark:bg-yellow-500/40 text-black dark:text-white font-extrabold px-1 rounded mx-[1px] underline decoration-2 decoration-yellow-400">{part}</span> 
                                          : part
                                     )}
                                  </p>
                              </div>
                          </div>
                      )})}
                  </div>
              </div>
          )}
       </div>
    </div>
  );
}