import React from 'react';

export default function Cell({
  // 💡 기본 짐 (UI, 네비게이션)
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 상태 및 데이터 짐
  date,
  currDay = {},
  authUser = {},
  globalCellData = {},
  
  // 💡 캔버스 및 에디터 짐
  renderToolbar,
  handleStickerAdd,
  handleMemoAdd,
  handleFileUpload,
  CanvasEngine,
  tool, setTool,
  color, setColor,
  size, setSize,
  StickerLayer,
  onPtrDown,
  
  // 💡 함수 짐
  updateDay,
  handleUpdateCell,
  handleAutoNumbering,
  handleAutoResize,
  copyCellReport,
  getArr,
  
  // 💡 아이콘 짐
  ReportIcon,
  BibleIcon,
  HeartIcon,
  PrayingHandsIcon,
  UserFaceIcon
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  // 1. 계산 로직
  const isAdmin = authUser?.role === 'admin';
  const cellData = globalCellData || { notice: '', submissions: [], groupPrayers: [], cellIntercession: '' };

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
      <SubPageHeader title="목장 모임" onBack={()=>setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
      
      {renderToolbar && renderToolbar(null, false, handleStickerAdd, handleMemoAdd, handleFileUpload)}
      
      {CanvasEngine && (
      <CanvasEngine key={`cell_${date}`} saveKey={`cell_${date}`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={currDay.memos} stickers={currDay.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} /> : null}>
        <div className="p-4 sm:p-6 flex flex-col gap-6 pb-40">
            <div className="flex justify-between items-center relative z-[45] pointer-events-auto">
               <h2 className={`text-lg md:text-xl font-black ${t.textMain}`}>[{authUser?.group || '소속 없음'}]</h2>
               {isAdmin && <span className="bg-red-50 dark:bg-red-900/20 text-red-500 text-[10px] font-bold px-2 py-1 rounded-full border border-red-200">🔥 관리자 접속중</span>}
            </div>
            
            <div className={`${t.cardBg} p-5 rounded-2xl shadow-sm border ${t.border} flex flex-col gap-2 relative z-[45] pointer-events-auto`}>
               <h3 className={`font-extrabold text-[13px] md:text-sm flex items-center gap-2 ${t.primaryText}`}>{ReportIcon && <ReportIcon className="w-5 h-5" isDark={isDarkMode}/>} 주간 공지사항 (주보)</h3>
               {isAdmin ? (
                   <textarea value={cellData.notice || ''} onChange={e=>handleUpdateCell && handleUpdateCell(p=>({...p, notice:e.target.value}))} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full mt-2 ${t.inputBg} ${t.textMain} p-3 rounded-xl text-xs md:text-sm border outline-none min-h-[80px] resize-none whitespace-pre-wrap`} />
               ) : (
                   <div className={`mt-2 p-3 ${t.appBg} rounded-xl text-xs md:text-sm font-medium ${t.textMain} whitespace-pre-wrap leading-relaxed`}>{cellData.notice || '등록된 공지사항이 없습니다.'}</div>
               )}
            </div>
            
            <div className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-4 relative z-[45] pointer-events-auto`}>
              <h3 className={`font-extrabold text-[13px] md:text-sm flex items-center gap-2 ${t.textMain}`}>✏️ 나의 나눔 작성하기</h3>
              <div className="flex flex-col gap-2">
                <span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} flex items-center gap-1`}>{BibleIcon && <BibleIcon className={`w-4 h-4 ${t.primaryText}`} isDark={isDarkMode}/>} 말씀 나눔</span>
                <textarea value={currDay.wordShare||''} onChange={(e)=>handleAutoNumbering && handleAutoNumbering(e, 'wordShare')} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full ${t.inputBg} ${t.textMain} p-4 rounded-xl text-xs md:text-sm border outline-none h-20 resize-none whitespace-pre-wrap`} placeholder="엔터를 치면 자동으로 번호가 매겨집니다." />
              </div>
              <div className={`w-full h-px ${t.border}`}></div>
              <div className="flex flex-col gap-2">
                <span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} flex items-center gap-1`}>{HeartIcon && <HeartIcon className={`w-4 h-4 ${t.pinkText}`} isDark={isDarkMode}/>} 감사 나눔</span>
                <textarea value={currDay.thanksShare||''} onChange={(e)=>handleAutoNumbering && handleAutoNumbering(e, 'thanksShare')} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full ${t.inputBg} ${t.textMain} p-4 rounded-xl text-xs md:text-sm border outline-none h-20 resize-none whitespace-pre-wrap`} placeholder="엔터를 치면 자동으로 번호가 매겨집니다." />
              </div>
              <div className={`w-full h-px ${t.border}`}></div>
              <div className="flex flex-col gap-2">
                <span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} flex items-center gap-1`}>{PrayingHandsIcon && <PrayingHandsIcon className={`w-4 h-4 ${t.yellowText}`} isDark={isDarkMode}/>} 개인 기도제목</span>
                <textarea value={currDay.prayerReq||''} onChange={(e)=>handleAutoNumbering && handleAutoNumbering(e, 'prayerReq')} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full ${t.inputBg} ${t.textMain} p-4 rounded-xl text-xs md:text-sm border outline-none h-20 resize-none whitespace-pre-wrap`} placeholder="엔터를 치면 자동으로 번호가 매겨집니다." />
              </div>
              <button onClick={() => { if(!currDay.prayerReq && !currDay.wordShare) return alert("나눔 내용이나 기도제목을 작성해주세요."); const submission = { id: Date.now(), name: authUser?.name, wordShare: currDay.wordShare, thanksShare: currDay.thanksShare, prayerReq: currDay.prayerReq, date: date }; if(handleUpdateCell) handleUpdateCell(p => ({ ...p, submissions: [submission, ...getArr(p.submissions)] })); alert("제출되었습니다!"); }} className={`w-full py-3 md:py-4 bg-blue-500 hover:bg-blue-600 text-white font-bold rounded-xl shadow-md transition-colors mt-2 text-sm`}>📤 목장 모임지 제출하기</button>
            </div>
            
            {isAdmin && (
              <div className={`${t.cardBg} p-5 rounded-2xl border-2 border-dashed border-red-300 dark:border-red-900 shadow-sm flex flex-col gap-4 relative z-[45] pointer-events-auto`}>
                <h3 className={`font-extrabold text-[13px] md:text-sm flex items-center gap-2 text-red-500`}>{UserFaceIcon && <UserFaceIcon className="w-5 h-5" isDark={isDarkMode}/>} [관리자 전용] 제출된 목원 나눔지</h3>
                {getArr(cellData.submissions).map(sub => (
                    <div key={sub.id} className={`p-4 ${t.appBg} rounded-xl border ${t.border} flex flex-col gap-2`}>
                        <div className="flex justify-between items-center mb-1">
                            <span className={`font-bold text-xs md:text-sm text-blue-500`}>👤 {sub.name} <span className="text-[9px] md:text-[10px] text-[#8E8E93] font-normal ml-2">{sub.date} 제출</span></span>
                            <button onClick={() => { if(handleUpdateCell) handleUpdateCell(p => ({...p, submissions: getArr(p.submissions).filter(x=>x.id!==sub.id)})); }} className="text-[9px] md:text-[10px] text-[#FF2D55] font-bold bg-[#FF2D55]/10 px-2 py-1 rounded">삭제</button>
                        </div>
                        {sub.wordShare && <p className={`text-[11px] md:text-xs ${t.textMain}`}><span className="font-bold text-[#8E8E93] block mb-1">말씀:</span> <span className="whitespace-pre-wrap">{sub.wordShare}</span></p>}
                        {sub.thanksShare && <p className={`text-[11px] md:text-xs ${t.textMain} mt-2`}><span className="font-bold text-[#8E8E93] block mb-1">감사:</span> <span className="whitespace-pre-wrap">{sub.thanksShare}</span></p>}
                        {sub.prayerReq && (
                            <div className={`mt-2 bg-blue-50 dark:bg-blue-900/20 p-2 md:p-3 rounded flex flex-col gap-2 border border-blue-100 dark:border-blue-800`}>
                               <p className={`text-[11px] md:text-xs ${t.textMain} font-bold break-all whitespace-pre-wrap`}><span className="text-orange-500 mb-1 block">기도:</span> {sub.prayerReq}</p>
                               <button onClick={() => { if(handleUpdateCell) handleUpdateCell(p => ({...p, groupPrayers: [{id: Date.now(), name: sub.name, text: sub.prayerReq, status: 'praying'}, ...getArr(p.groupPrayers)] })); alert(`${sub.name}님의 기도제목이 승인되었습니다.`); }} className="text-[9px] md:text-[10px] bg-blue-500 text-white px-2 py-1.5 rounded shadow-sm hover:opacity-90 self-end">식구 기도제목으로 올리기</button>
                            </div>
                        )}
                    </div>
                ))}
                {getArr(cellData.submissions).length === 0 && <p className="text-center text-[11px] md:text-xs text-[#8E8E93] py-4">새로 제출된 모임지가 없습니다.</p>}
              </div>
            )}
            
            <div className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-4 relative z-[45] pointer-events-auto`}>
                <div className={`flex justify-between items-center border-b ${t.border} pb-3 mb-2`}>
                   <h3 className={`font-extrabold text-[13px] md:text-sm flex items-center gap-2 ${t.textMain}`}>{PrayingHandsIcon && <PrayingHandsIcon className={`w-5 h-5 ${t.greenText}`} isDark={isDarkMode}/>} 전체 식구 기도제목</h3>
                   <button onClick={copyCellReport} className={`text-[9px] md:text-[10px] ${t.appBg} ${t.textMain} font-bold px-2 py-1 rounded shadow-sm border ${t.border}`}>보고서 복사</button>
                </div>
                <div className={`p-4 rounded-xl border border-dashed border-green-300 dark:border-green-800 bg-green-50/50 dark:bg-green-900/10 mb-2`}>
                   <span className={`text-[10px] md:text-[11px] font-bold ${t.greenText} mb-1 block`}>⛪ 목장 중보기도</span>
                   {isAdmin ? (
                       <textarea value={cellData.cellIntercession||''} onChange={e=>handleUpdateCell && handleUpdateCell(p=>({...p, cellIntercession: e.target.value}))} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full p-2 bg-transparent text-[11px] md:text-xs font-bold ${t.textMain} outline-none border-b border-green-200 dark:border-green-800 resize-none h-16 whitespace-pre-wrap`} placeholder="이번 주 목장 전체를 위한 중보기도 제목..." />
                   ) : (
                       <div className={`text-[11px] md:text-xs font-medium ${t.textMain} whitespace-pre-wrap leading-relaxed`}>{cellData.cellIntercession || '등록된 목장 중보기도가 없습니다.'}</div>
                   )}
                </div>
                <div className="flex flex-col gap-3 max-h-[300px] overflow-y-auto hide-scrollbar">
                    {getArr(cellData.groupPrayers).map(gp => (
                        <div key={gp.id} className={`flex items-start gap-2 p-3 rounded-xl border ${gp.status==='answered' ? 'bg-green-50/50 dark:bg-green-900/10 border-green-100 dark:border-green-800 opacity-60' : `${t.appBg} ${t.border}`}`}>
                            <div className="flex-1 flex flex-col">
                               <span className={`text-[10px] md:text-[11px] font-black ${gp.status==='answered'? t.greenText : t.primaryText}`}>{gp.name}</span>
                               <span className={`text-[11px] md:text-xs font-medium ${t.textMain} mt-0.5 whitespace-pre-wrap ${gp.status==='answered'?'line-through':''}`}>{gp.text}</span>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      </CanvasEngine>
      )}
    </div>
  );
}