                    {[0, 1].map((i) => ( <div key={i} className="flex flex-col gap-1"><span className={`text-[10px] md:text-[11px] font-bold ${t.textSub}`}>{i+1}번째 감사 선포</span><textarea value={(mLocal.thanksDeclarations || ['',''])[i]||''} onChange={(e) => { const next = [...(mLocal.thanksDeclarations || ['',''])]; next[i] = e.target.value; setMLocal({...mLocal, thanksDeclarations: next}); updateDay({thanksDeclarations: next, checks: { ...(currDay.checks||{}), '감사': true }}); }} onInput={handleAutoResize} className={`w-full p-3 md:p-4 rounded-xl ${t.inputBg} ${t.textMain} min-h-[60px] resize-none overflow-hidden border outline-none text-[12px] md:text-[13px] whitespace-pre-wrap`} placeholder="나는 ~를 감사합니다." onPointerDown={e => e.stopPropagation()} /></div> ))}
