                      <button onClick={()=>{setMLocal([...getArr(mLocal), {id:Date.now(), text:'', status:'praying'}]); updateDay({ checks: { ...(currDay.checks||{}), '기도하기': true } });}} className={`w-full text-[10px] md:text-[11px] ${t.textSub} mt-2 font-bold py-2 border border-dashed border-[#8E8E93] rounded-lg`}>+ 기도제목 추가</button>
