import React, { useState, useEffect, useRef } from 'react';

const getArr = (val, def = []) => Array.isArray(val) ? val : def;
const safeParse = (key, def) => { try { const val = localStorage.getItem(key); if (!val) return def; const parsed = JSON.parse(val); return parsed !== null ? parsed : def; } catch(e) { return def; } };
const safeSetItem = (key, value) => { try { localStorage.setItem(key, value); } catch (e) { console.warn(`[용량 초과 방어] ${key} 저장 실패`); } };

export const renderPath = (ctx, el) => {
    if (!el.points || el.points.length < 1) return;
    ctx.save();
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    if (el.tool === 'fountain') {
        ctx.strokeStyle = el.color;
        ctx.shadowColor = "rgba(0,0,0,0.3)";
        ctx.shadowBlur = 2;
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) ctx.lineTo(el.points[i].x, el.points[i].y);
        ctx.lineWidth = el.size;
        ctx.stroke();
    } else if (el.tool === 'charcoal') {
        ctx.strokeStyle = el.color;
        ctx.globalAlpha = 0.7;
        ctx.lineWidth = el.size * 1.5;
        ctx.lineCap = 'square';
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) {
            const jitterX = (Math.random() - 0.5) * 2;
            const jitterY = (Math.random() - 0.5) * 2;
            ctx.lineTo(el.points[i].x + jitterX, el.points[i].y + jitterY);
        }
        ctx.stroke();
    } else if (el.tool === 'highlighter') {
        ctx.strokeStyle = el.color;
        ctx.lineWidth = el.size * 2;
        ctx.globalAlpha = 0.4;
        ctx.shadowColor = el.color;
        ctx.shadowBlur = 3;
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) ctx.lineTo(el.points[i].x, el.points[i].y);
        ctx.stroke();
    } else if (el.tool === 'pastel') {
        ctx.strokeStyle = el.color;
        ctx.lineWidth = el.size * 2.5;
        ctx.globalAlpha = 0.3;
        ctx.shadowBlur = el.size * 1.5;
        ctx.shadowColor = el.color;
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) ctx.lineTo(el.points[i].x, el.points[i].y);
        ctx.stroke();
    } else if (el.tool === 'crayon') {
        ctx.strokeStyle = el.color;
        ctx.globalAlpha = 0.85;
        ctx.lineWidth = el.size * 1.2;
        ctx.beginPath();
        el.points.forEach((p, i) => {
            const jitterX = (Math.sin(p.x * 12.9 + p.y * 78.2) * 1.8);
            const jitterY = (Math.cos(p.x * 12.9 + p.y * 78.2) * 1.8);
            if(i===0) ctx.moveTo(p.x + jitterX, p.y + jitterY);
            else ctx.lineTo(p.x + jitterX, p.y + jitterY);
        });
        ctx.stroke();
    } else if (el.tool === 'pencil') {
        ctx.strokeStyle = el.color;
        ctx.lineWidth = Math.max(1, el.size * 0.6);
        ctx.globalAlpha = 0.8;
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) ctx.lineTo(el.points[i].x, el.points[i].y);
        ctx.stroke();
    } else if (el.tool === 'pen') {
        ctx.strokeStyle = el.color;
        ctx.lineWidth = el.size * 0.8;
        ctx.globalAlpha = 1.0;
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) ctx.lineTo(el.points[i].x, el.points[i].y);
        ctx.stroke();
    } else if (el.tool === 'arrow' || el.tool === 'arrow-s' || el.tool === 'arrow-tw') {
        ctx.lineWidth = el.size;
        ctx.strokeStyle = el.color; 
        ctx.fillStyle = el.color;   
        ctx.globalAlpha = 1.0;
        ctx.shadowBlur = 0;

        const pStart = el.points[0];
        const pEnd = el.points[el.points.length - 1];
        
        if (Math.hypot(pEnd.x - pStart.x, pEnd.y - pStart.y) > 5) {
            const angle = Math.atan2(pEnd.y - pStart.y, pEnd.x - pStart.x);
            const headLen = 15 + el.size;
            
            const lineEndX = pEnd.x - headLen * Math.cos(angle) * 0.8;
            const lineEndY = pEnd.y - headLen * Math.sin(angle) * 0.8;

            ctx.beginPath();
            ctx.moveTo(pStart.x, pStart.y);

            if (el.tool === 'arrow-s') {
                const cp1x = pStart.x + (lineEndX - pStart.x) / 2;
                const cp1y = pStart.y - 40;
                const cp2x = pStart.x + (lineEndX - pStart.x) / 2;
                const cp2y = lineEndY + 40;
                ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, lineEndX, lineEndY);
            } else if (el.tool === 'arrow-tw') {
                const mx = (pStart.x + lineEndX) / 2;
                const my = (pStart.y + lineEndY) / 2;
                const dx = -(lineEndY - pStart.y);
                const dy = (lineEndX - pStart.x);
                const len = Math.hypot(dx, dy);
                const nx = (dx/len) * 35;
                const ny = (dy/len) * 35;
                ctx.quadraticCurveTo(mx + nx, my + ny, lineEndX, lineEndY);
            } else {
                ctx.lineTo(lineEndX, lineEndY);
            }
            ctx.stroke();

            ctx.beginPath();
            ctx.moveTo(pEnd.x, pEnd.y);
            ctx.lineTo(pEnd.x - headLen * Math.cos(angle - Math.PI / 6), pEnd.y - headLen * Math.sin(angle - Math.PI / 6));
            ctx.lineTo(pEnd.x - headLen * Math.cos(angle + Math.PI / 6), pEnd.y - headLen * Math.sin(angle + Math.PI / 6));
            ctx.closePath();
            ctx.fill();
        }
    } else {
        ctx.strokeStyle = el.color;
        ctx.lineWidth = el.size;
        ctx.beginPath(); ctx.moveTo(el.points[0].x, el.points[0].y);
        for(let i=1; i<el.points.length; i++) ctx.lineTo(el.points[i].x, el.points[i].y);
        ctx.stroke();
    }
    ctx.restore();
};

export function StickerLayer({ memos, stickers, onUpdateMemos, onUpdateStickers, onPtrDown }) {
  return (
    <div className="absolute inset-0 z-40 pointer-events-none overflow-hidden">
       {getArr(memos).map(memo => {
            const st = memo.animal==='🐰' ? {bg:'bg-pink-50', bd:'border-pink-200', hd:'bg-pink-100 text-pink-800'} : {bg:'bg-orange-50', bd:'border-orange-200', hd:'bg-orange-100 text-orange-800'};
            return (
              <div key={memo.id} onPointerDown={(e) => onPtrDown(e, memo, 'memo')} className={`absolute shadow-xl border backdrop-blur-sm flex flex-col pointer-events-auto touch-none cursor-move rounded-2xl ${st.bg}${st.bd}`} style={{ left: memo.x, top: memo.y, minWidth: '130px' }}>
                <div className={`py-1 px-2 font-bold text-[11px] ${st.hd} flex justify-between items-center select-none rounded-t-2xl`}><span>{memo.animal} 메모</span><button onPointerDown={(e)=>e.stopPropagation()} onClick={() => onUpdateMemos(getArr(memos).filter(m => m.id !== memo.id))} className="text-slate-400 hover:text-red-500 font-bold bg-white/80 rounded-full w-4 h-4 flex items-center justify-center text-[10px] ignore-draw">×</button></div>
                <textarea className="w-full bg-transparent resize h-20 p-2 text-xs outline-none text-slate-800 ignore-draw" placeholder="메모 내용..." value={memo.text} onChange={(e) => onUpdateMemos(getArr(memos).map(m => m.id === memo.id ? {...m, text: e.target.value} : m))} onPointerDown={(e) => e.stopPropagation()} />
              </div>
            );
       })}
       {getArr(stickers).map(stk => (
         <div key={stk.id} onPointerDown={(e) => onPtrDown(e, stk, 'sticker')} className="absolute cursor-move text-5xl hover:scale-105 transition-transform select-none pointer-events-auto touch-none group" style={{ left: stk.x, top: stk.y }}>
           <button onPointerDown={(e)=>e.stopPropagation()} onClick={() => onUpdateStickers(getArr(stickers).filter(s => s.id !== stk.id))} className="absolute -top-2 -right-2 bg-white/90 text-slate-500 border border-slate-200 rounded-full w-5 h-6 flex items-center justify-center text-[10px] font-bold opacity-0 group-hover:opacity-100 shadow-sm transition-opacity ignore-draw z-50">×</button>
           {stk.isEmoji ? stk.src : <img src={stk.src} alt="sticker" className="w-20 drop-shadow-sm pointer-events-none" draggable="false" />}
         </div>
       ))}
    </div>
  );
}

export function CanvasEngine({ saveKey, tool, setTool, color, setColor, size, setSize, t, renderStickers, children }) {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const [elements, setElements] = useState(() => safeParse(`custom_native_canvas_${saveKey}`, []));
  const isDrawingRef = useRef(false);
  const currentPathRef = useRef(null);

  useEffect(() => { setElements(safeParse(`custom_native_canvas_${saveKey}`, [])); }, [saveKey]);

  useEffect(() => {
    safeSetItem(`custom_native_canvas_${saveKey}`, JSON.stringify(elements));
    redrawCanvas();
  }, [elements, saveKey]);

  const redrawCanvas = () => {
    const canvas = canvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    getArr(elements).forEach(el => renderPath(ctx, el));
    if (currentPathRef.current) renderPath(ctx, currentPathRef.current);
  };

  useEffect(() => {
    let debounceTimer = null;
    const handleResize = () => {
      if (containerRef.current && canvasRef.current) {
        canvasRef.current.width = containerRef.current.offsetWidth;
        canvasRef.current.height = Math.max(containerRef.current.scrollHeight, containerRef.current.offsetHeight, window.innerHeight * 1.5);
        redrawCanvas();
      }
    };
    const observer = new ResizeObserver(() => { clearTimeout(debounceTimer); debounceTimer = setTimeout(handleResize, 100); });
    if (containerRef.current) observer.observe(containerRef.current);
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => { window.removeEventListener('resize', handleResize); observer.disconnect(); clearTimeout(debounceTimer); };
  }, [elements]);

  const getPos = (e) => {
    const canvas = canvasRef.current; if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const clientX = e.touches && e.touches.length > 0 ? e.touches[0].clientX : (e.changedTouches && e.changedTouches.length > 0 ? e.changedTouches[0].clientX : e.clientX);
    const clientY = e.touches && e.touches.length > 0 ? e.touches[0].clientY : (e.changedTouches && e.changedTouches.length > 0 ? e.changedTouches[0].clientY : e.clientY);
    return { x: clientX - rect.left, y: clientY - rect.top };
  };

  const handleMouseDown = (e) => {
    if (tool === 'hand') return;
    const pos = getPos(e);
    if (tool === 'eraser') {
      setElements(prev => getArr(prev).filter(el => {
        if (el.points) return !getArr(el.points).some(p => Math.hypot(p.x - pos.x, p.y - pos.y) < 18);
        return true;
      })); return;
    }
    
    isDrawingRef.current = true;
    currentPathRef.current = { type: 'freehand', tool, color, size, points: [pos] };
  };

  const handleMouseMove = (e) => {
    if (!isDrawingRef.current) return;
    const pos = getPos(e);
    
    if (currentPathRef.current) {
        const pts = getArr(currentPathRef.current.points);
        if (pts.length > 0 && Math.hypot(pos.x - pts[pts.length - 1].x, pos.y - pts[pts.length - 1].y) > 4) {
            pts.push(pos);
            redrawCanvas();
        }
    }
  };

  const handleMouseUp = (e) => {
    if (!isDrawingRef.current) return;
    isDrawingRef.current = false;
    
    if (currentPathRef.current && getArr(currentPathRef.current.points).length > 1) {
      setElements(prev => [...getArr(prev), currentPathRef.current]);
    }
    currentPathRef.current = null; redrawCanvas();
  };

  return (
    <div ref={containerRef} className={`relative flex-1 w-full overflow-y-auto scroll-smooth hide-scrollbar ${t.pageBg}`} style={{ touchAction: tool === 'hand' ? 'pan-y pan-x' : 'none' }}>
      <div className="relative w-full min-h-[140vh] flex flex-col" style={{ height: 'max-content' }}>
        {renderStickers && renderStickers()}
        <div className={`absolute inset-0 z-30 ${tool === 'hand' ? 'pointer-events-none' : 'pointer-events-auto'}`}>
          <canvas ref={canvasRef} className="absolute inset-0 w-full h-full cursor-crosshair" onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onTouchStart={handleMouseDown} onTouchMove={handleMouseMove} onTouchEnd={handleMouseUp} />
        </div>
        <div className="relative z-20 flex-1 flex flex-col pointer-events-auto">
          {children}
        </div>
      </div>
    </div>
  );
}