import React, { useState, useRef, useMemo, useEffect } from 'react';
import RichTextEditor from '../components/RichTextEditor';

export default function Mcheyne({
  // 💡 기본 짐 (UI, 네비게이션)
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 상태 및 데이터 짐
  date,
  currDay = {},
  ymdStr,
  bibles = [],
  mcheyneActivePlan = [],
  mcheynePlanIdx,
  setMcheynePlanIdx,
  readVerses = {},
  setReadVerses,
  ttsRate,
  setTtsRate,
  isSpeaking,
  
  // 💡 캔버스 및 에디터 짐
  mcheyneEditorRef,
  renderToolbar,
  handleStickerAdd,
  handleMemoAdd,
  handleFileUpload,
  CanvasEngine,
  tool, setTool,
  color, setColor,
  size, setSize,
  StickerLayer,
  onPtrDown,
  
  // 💡 함수 짐
  updateDay,
  getArr,
  cleanText,
  toggleTTS,
  handleAutoResize,
  
  // 💡 아이콘 짐
  YoutubeIcon
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  // 1. 계산 로직
  const mpList = mcheyneActivePlan || []; 
  const mp = mpList[mcheynePlanIdx] || mpList[0]; 
  const mBookD = mp ? (getArr(bibles).find(b => b.name === mp.book) || bibles[0]) : bibles[0]; 
  
  const mChaps = mp 
    ? String(mp.chapterString).includes('-') 
      ? Array.from({length: parseInt(String(mp.chapterString).split('-')[1]) - parseInt(String(mp.chapterString).split('-')[0]) + 1}, (_, i) => parseInt(String(mp.chapterString).split('-')[0]) + i) 
      : [parseInt(String(mp.chapterString))] 
    : [1]; 
    
  const mAllR = getArr(mChaps).every(ch => 
    getArr(getArr(mBookD?.chapters)[ch-1]).every((_, i) => (readVerses||{})[`${mBookD?.name}-${ch}-${i}`])
  );

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
      <SubPageHeader title="오늘의 맥체인" onBack={()=>setActiveScreen('fiveSetMenu')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
      
      <div className={`${t.cardBg} px-4 md:px-6 pt-3 pb-4 shadow-sm z-[60] border-b ${t.border} shrink-0 pointer-events-auto relative`}>
        <div className="flex flex-col gap-2 md:gap-3 relative mb-3 md:mb-4">
          <div><p className={`text-[13px] md:text-sm font-bold ${t.textMain}`}>{mp ? cleanText(mp.title) : ''}</p></div>
          <div className="flex flex-wrap gap-1.5">
            <button onClick={()=>setTtsRate && setTtsRate(r => r===1.0 ? 1.2 : r===1.2 ? 1.5 : r===1.5 ? 2.0 : 1.0)} className={`h-7 md:h-8 px-2 rounded text-[10px] md:text-xs font-bold border ${t.border} ${t.textMain} shadow-sm`}>{ttsRate}x 배속</button>
            <button onClick={()=>{ 
                const q = [`${mp?.title} 말씀입니다.`]; 
                getArr(mChaps).forEach(ch => { getArr(getArr(mBookD?.chapters)[ch-1]).forEach(v => q.push(cleanText(v))); }); 
                if(toggleTTS) toggleTTS(q); 
            }} className={`h-7 md:h-8 px-2 md:px-2.5 rounded text-[10px] md:text-xs font-bold ${isSpeaking?`bg-[#FFB7B2] text-[#1D1D1F] animate-pulse`:`${t.primaryBg} text-white dark:text-[#1D1D1F]`} shadow-sm`}>
                {isSpeaking?'⏹️ 중지':'🔊 낭독'}
            </button>
            <a href={`https://www.youtube.com/results?search_query=부산신성교회+맥체인+성경읽기+${ymdStr}`} target="_blank" rel="noreferrer" className={`h-7 md:h-8 px-2 md:px-2.5 rounded text-[10px] md:text-xs font-bold bg-[#8AB4F8] text-[#1D1D1F] shadow-sm flex items-center`}>
                {YoutubeIcon && <YoutubeIcon className="w-3.5 h-3.5 mr-1" isDark={isDarkMode}/>}듣기
            </a>
            <a href={`https://www.youtube.com/results?search_query=부산신성교회+맥체인+성경+해설+${ymdStr}`} target="_blank" rel="noreferrer" className={`h-7 md:h-8 px-2 md:px-2.5 rounded text-[10px] md:text-xs font-bold ${isDarkMode ? 'bg-[#2C2C2E] text-white' : 'bg-slate-200 text-slate-900'} shadow-sm flex items-center`}>💡 해설</a>
          </div>
        </div>
        <div className="flex gap-2 overflow-x-auto hide-scrollbar pb-1">
          {getArr(mpList).map((planItem, idx) => ( 
              <button key={idx} onClick={() => setMcheynePlanIdx && setMcheynePlanIdx(idx)} className={`h-8 md:h-10 px-3 md:px-4 rounded-xl text-[11px] md:text-xs font-bold whitespace-nowrap shrink-0 border transition-colors ${mcheynePlanIdx === idx ? `${t.primaryBg} text-white dark:text-[#1D1D1F] border-transparent` : `${t.appBg} ${t.textSub} hover:opacity-80`}`}>{cleanText(planItem.title)}</button> 
          ))}
        </div>
      </div>

      {renderToolbar && renderToolbar(mcheyneEditorRef, false, handleStickerAdd, handleMemoAdd, handleFileUpload)}

      {CanvasEngine && (
      <CanvasEngine key={`mcheyne_${date}_${mcheynePlanIdx}`} saveKey={`mcheyne_${date}_${mcheynePlanIdx}`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={currDay.memos} stickers={currDay.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} /> : null}>
        <div className="p-4 sm:p-6 flex flex-col sm:flex-row gap-5 md:gap-8 items-stretch pb-40 flex-1 relative z-10">
            <div className={`flex-1 break-words ${t.cardBg} border ${t.border} rounded-2xl p-4 md:p-5 shadow-sm relative z-[45] pointer-events-auto`}>
                {getArr(mChaps).map(ch => ( 
                    <div key={ch} className="mb-6 md:mb-8">
                        <h4 className={`font-extrabold ${t.primaryText} text-[13px] md:text-sm mb-3 md:mb-4 border-b ${t.border} pb-2`}>제 {ch} 장</h4>
                        {getArr(getArr(mBookD?.chapters)[ch - 1]).map((verse, idx) => { 
                            const vId = `${mBookD?.name}-${ch}-${idx}`; 
                            const isRead = (readVerses||{})[vId]; 
                            return ( 
                                <p key={idx} onClick={() => { if(tool==='hand' && setReadVerses) setReadVerses(p => ({ ...p, [vId]: !p[vId] })); }} className={`flex gap-2 md:gap-3 p-2 md:p-3 rounded-xl mb-1 cursor-pointer text-[13px] md:text-sm sm:text-base transition-colors ${isRead ? `opacity-40 grayscale text-[#8E8E93]` : `hover:${t.highlight} ${t.textMain}`}`}>
                                    <span className={`font-bold min-w-[1.2rem] md:min-w-[1.5rem] text-right mt-0.5 ${t.primaryText}`}>{idx + 1}</span>
                                    <span>{cleanText(verse)}</span>
                                </p> 
                            ); 
                        })}
                    </div> 
                ))}
                <button onClick={() => { 
                    const u = {}; 
                    const s = !mAllR; 
                    getArr(mChaps).forEach(ch => { getArr(getArr(mBookD?.chapters)[ch-1]).forEach((_, i) => u[`${mBookD?.name}-${ch}-${i}`] = s); }); 
                    if(setReadVerses) setReadVerses(p => ({...p, ...u})); 
                    if (s && updateDay) updateDay({ checks: { ...(currDay.checks||{}), '성경읽기': true } }); 
                }} className={`w-full mt-4 md:mt-6 py-3 md:py-4 rounded-2xl font-bold text-[13px] md:text-sm sm:text-base transition-all ignore-draw ${mAllR ? `${t.appBg} ${t.textSub} border ${t.border}` : `${t.primaryBg} text-white dark:text-[#1D1D1F] shadow-sm hover:opacity-90`}`}>
                    {mAllR ? '🔄 전체 읽음 취소' : '📖 이 구절들을 모두 읽음 표시'}
                </button>
            </div>
            <div className={`hidden sm:flex flex-1 flex-col ${t.cardBg} border ${t.border} shadow-sm rounded-2xl overflow-hidden min-h-[500px] relative z-[45] pointer-events-auto`}>
    <div className={`p-3 border-b ${t.border} ${t.appBg} flex justify-between items-center z-10 ignore-draw`}>
        <span className={`text-[11px] md:text-xs font-bold ml-2 ${t.textSub}`}>📝 맥체인 묵상 노트 (성경 구절 타이핑 가능)</span>
    </div>
    <RichTextEditor 
        ref={mcheyneEditorRef} 
        value={currDay.mcheyneNote || ''} 
        onChange={val => updateDay({ mcheyneNote: val })} 
        t={t} 
        bibles={bibles} 
        placeholder="구절(예: 창세기 1:1)을 입력하고 스페이스바를 누르면 본문이 삽입됩니다..." 
    />
</div>
        </div>
      </CanvasEngine>
      )}
    </div>
  );
}