// 💡 더욱 강력해진 자동 디코딩 엔진 (띄어쓰기 오타가 있어도 고장 나지 않음)
export const getMcheynePlan = (monthDay) => {
  const dataString = rawMcheyne365[monthDay];
  if (!dataString) return null;

  const parts = dataString.split(',').map(s => s.trim());
  const labels = ["가정1", "가정2", "개인1", "개인2"];
  
  return parts.map((part, index) => {
    let bookAbbr = "";
    let chapInfo = "";
    
    // 띄어쓰기가 있는지 확인
    const spaceIdx = part.indexOf(' ');
    
    if (spaceIdx !== -1) {
      // 띄어쓰기가 정상적으로 있다면, 그 기준으로 분리
      bookAbbr = part.substring(0, spaceIdx).trim();
      chapInfo = part.substring(spaceIdx + 1).trim();
    } else {
      // 실수로 띄어쓰기를 빼먹었을 경우 (예: "js6") 영문자와 숫자를 강제로 분리하는 방어 로직
      const match = part.match(/^([a-zA-Z0-9]+?)([0-9\-~]+)$/);
      if(match) {
        bookAbbr = match[1];
        chapInfo = match[2];
      } else {
        bookAbbr = part;
        chapInfo = "1";
      }
    }
    
    const engName = abbrToEng[bookAbbr] || bookAbbr;
    const koName = bookNamesKo[engName] || engName;

    return {
      book: engName,
      chapterString: chapInfo,
      title: `${koName} ${chapInfo}장 (${labels[index]})`
    };
  });
};