import React from 'react';

export default function QT({
  // 💡 기본 짐 (UI, 네비게이션)
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 상태 및 데이터 짐
  date,
  currDay = {},
  dailyData = {},
  globalSharedQt = {},
  isWknd,
  ymdStr,
  
  // 💡 캔버스 및 에디터 짐
  qtEditorRef,
  renderToolbar,
  handleStickerAdd,
  handleMemoAdd,
  handleFileUpload,
  CanvasEngine,
  tool, setTool,
  color, setColor,
  size, setSize,
  StickerLayer,
  onPtrDown,
  
  // 💡 함수 짐
  updateDay,
  extractVideoId,
  handleUpdateSharedQt,
  triggerConfetti,
  findBibleText,
  handleAutoResize,
  
  // 💡 아이콘 짐
  YoutubeIcon,
  SmileFaceIcon,
  ReportIcon,
  BibleIcon,
  PrayingHandsIcon
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  // 1. 계산 로직
  const sharedVidId = globalSharedQt[date]?.qt || currDay.qtVideoId;
  
  const qtStreak = (() => { 
    let mx=0, cur=0; 
    const sD=Object.keys(dailyData).sort(); 
    if(!sD.length) return 0; 
    let pD=new Date(sD[0]); 
    if(isNaN(pD)) return 0; 
    pD.setDate(pD.getDate()-2); 
    sD.forEach(d => { 
      if(dailyData[d]?.checks?.['QTin']) { 
        const cD=new Date(d); 
        if(Math.ceil(Math.abs(cD-pD)/86400000)===1) cur++; 
        else cur=1; 
        if(cur>mx) mx=cur; 
        pD=cD; 
      } 
    }); 
    return mx; 
  })();
  
  const currYear = parseInt(date.substring(0,4));
  const currMonth = parseInt(date.substring(5,7));
  const daysInMonth = new Date(currYear, currMonth, 0).getDate();
  const firstDayOfWeek = new Date(currYear, currMonth - 1, 1).getDay();

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
      <SubPageHeader title="매일 QT 챌린지" onBack={() => setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
      
      {renderToolbar && renderToolbar(qtEditorRef, true, handleStickerAdd, handleMemoAdd, handleFileUpload)}
      
      {CanvasEngine && (
      <CanvasEngine key={`qt_${date}`} saveKey={`qt_${date}`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={currDay.memos} stickers={currDay.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} /> : null}>
        <div className="p-4 sm:p-6 flex flex-col lg:flex-row gap-5 md:gap-8 pb-40 md:pb-20 items-stretch">
          <div className="flex-1 flex flex-col gap-5 min-w-0">
            <div className="flex justify-between items-center px-1"><span className={`text-xs md:text-sm font-bold ${t.textMain}`}>연속 달성 기록</span><span className={`text-xl md:text-2xl font-black ${t.primaryText}`}>{qtStreak}일</span></div>
            <div className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-4 relative z-[45] pointer-events-auto`}>
                <div className="flex justify-between items-center">
                  <h3 className={`font-bold ${t.textMain} text-[13px] md:text-sm flex items-center gap-2`}>{YoutubeIcon && <YoutubeIcon className={`w-5 h-5 ${t.pinkText}`} isDark={isDarkMode}/>} 오늘의 큐티 영상</h3>
                  <a href={`https://www.youtube.com/results?search_query=${isWknd ? '우리들교회+큐티인+새벽기도회' : '우리들교회+김양재+목사+큐티노트'}+${ymdStr}`} target="_blank" rel="noreferrer" className={`text-[9px] md:text-[10px] bg-red-50 dark:bg-red-900/20 text-red-500 px-2 py-1 rounded font-bold shadow-sm`}>검색하기 ↗</a>
                </div>
                <div className="flex gap-2">
                    <input type="text" placeholder="검색한 영상 링크 붙여넣기..." value={currDay.qtVideoUrl || ''} onChange={(e) => { const url = e.target.value; const vId = extractVideoId ? extractVideoId(url) : null; updateDay && updateDay({ qtVideoUrl: url, qtVideoId: vId !== null ? vId : '', checks: { ...(currDay.checks||{}), 'QTin': true } }); }} onPointerDown={e => e.stopPropagation()} className={`flex-1 h-10 px-3 rounded-lg text-[10px] md:text-xs font-bold border outline-none ${t.inputBg} ${t.textMain}`} />
                    <button onClick={() => { if(!currDay.qtVideoId) return alert("먼저 올바른 유튜브 링크를 넣어주세요."); handleUpdateSharedQt && handleUpdateSharedQt(date, 'qt', currDay.qtVideoId); alert("공유되었습니다!"); }} className="bg-[#F48FB1] text-white dark:text-[#1D1D1F] px-3 py-1 rounded-lg text-[10px] md:text-xs font-bold shadow-sm hover:opacity-90 transition-colors shrink-0">앱 전체 공유</button>
                </div>
                <div className={`w-full aspect-video bg-black rounded-xl overflow-hidden shadow-sm relative border ${t.border}`}>
                  {sharedVidId ? <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${sharedVidId}?rel=0`} title="QT Video" frameBorder="0" allowFullScreen className="absolute inset-0 w-full h-full"></iframe> : <div className="absolute inset-0 flex flex-col items-center justify-center text-[#8E8E93] text-[10px] md:text-xs gap-2">{YoutubeIcon && <YoutubeIcon className="w-8 h-8 opacity-40" isDark={isDarkMode}/>}영상을 검색해 링크를 넣으면 공유됩니다.</div>}
                </div>
                <button onClick={() => { updateDay && updateDay({ checks: { ...(currDay.checks||{}), 'QTin': true } }); triggerConfetti && triggerConfetti(); alert("시청 완료 체크가 되었습니다!"); }} className={`w-full py-2.5 rounded-lg text-[11px] md:text-xs font-bold ${t.appBg} ${t.textMain} border ${t.border} hover:opacity-80`}>✅ 영상 시청 완료 체크</button>
            </div>
            
            <div className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-4 relative z-[45] pointer-events-auto`}>
                <div className="flex flex-col gap-1.5"><span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase`}>✍️ 큐티 제목</span><input type="text" value={currDay.qtTitle||''} onChange={e=>updateDay && updateDay({qtTitle: e.target.value, checks: { ...(currDay.checks||{}), 'QTin': true }})} onPointerDown={e => e.stopPropagation()} placeholder="큐티 제목..." className={`w-full h-10 md:h-12 px-4 rounded-xl text-[11px] md:text-sm font-bold border outline-none ${t.inputBg} ${t.textMain}`} /></div>
                <div className="flex flex-col gap-1.5"><span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase`}>📖 성경 본문</span>
                  <div className="flex gap-2"><input type="text" value={currDay.qtReference||''} onChange={e=>updateDay && updateDay({qtReference: e.target.value, checks: { ...(currDay.checks||{}), 'QTin': true }})} onPointerDown={e => e.stopPropagation()} placeholder="예: 요한복음 3장 16절" className={`flex-1 h-10 md:h-12 px-4 rounded-xl text-[11px] md:text-sm font-bold border outline-none ${t.inputBg} ${t.textMain}`} /><button onClick={()=>findBibleText && findBibleText(currDay.qtReference)} className={`h-10 md:h-12 px-4 md:px-5 ${t.primaryBg} hover:opacity-80 text-white dark:text-[#1D1D1F] rounded-xl text-[11px] md:text-sm font-bold ignore-draw`}>찾기</button></div>
                </div>
            </div>

            <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex-1 relative z-[45] pointer-events-auto`}>
                <h3 className={`font-bold ${t.textMain} text-[13px] md:text-sm mb-4 border-b ${t.border} pb-3 flex items-center gap-1.5`}>{SmileFaceIcon && <SmileFaceIcon className={`w-4 h-4 ${t.yellowText}`} isDark={isDarkMode}/>} 📆 이달의 QT 스탬프 챌린지 ({currMonth}월)</h3>
                <div className="grid grid-cols-7 gap-1 md:gap-2 text-center mb-2 md:mb-3">{['일', '월', '화', '수', '목', '금', '토'].map((w, i) => <div key={w} className={`text-[9px] md:text-[11px] font-bold ${i===0 ? t.pinkText : i===6 ? t.primaryText : t.textSub}`}>{w}</div>)}</div>
                <div className="grid grid-cols-7 gap-1 md:gap-2">
                  {Array.from({length: firstDayOfWeek}, (_, i) => i).map(e => <div key={`empty-${e}`} className="aspect-square" />)}
                  {Array.from({length: daysInMonth}, (_, i) => i + 1).map(day => {
                      const dStr = `${currYear}-${String(currMonth).padStart(2, '0')}-${String(day).padStart(2, '0')}`; 
                      const isS = dailyData[dStr]?.checks?.['QTin'] === true; 
                      const isT = dStr === date; 
                      const dOw = (firstDayOfWeek + day - 1) % 7;
                      return (
                        <div key={day} onClick={() => { const nS = !isS; updateDay && updateDay({ checks: { ...(currDay.checks||{}), 'QTin': nS } }); if (nS && triggerConfetti) triggerConfetti(); }} className="relative flex items-center justify-center aspect-square transition-all cursor-pointer select-none group w-full h-full">
                          <div className={`absolute inset-0 rounded-full transition-colors ${isT ? t.appBg : ``}`}></div>
                          <span className={`relative z-10 font-bold text-[10px] md:text-[13px] ${dOw === 0 ? t.pinkText : dOw === 6 ? t.primaryText : t.textSub} ${isT && !isS ? t.textMain : ''}`}>{day}</span>
                          {isS && <div className="absolute inset-[10%] flex items-center justify-center z-20 pointer-events-none drop-shadow-md bg-white/90 dark:bg-[#121212]/90 rounded-full">{SmileFaceIcon && <SmileFaceIcon className={`w-full h-full p-1 ${t.yellowText} rotate-[-10deg] animate-bounce`} isDark={isDarkMode}/>}</div>}
                        </div>
                      );
                  })}
                </div>
            </div>
          </div>
          
          <div className={`flex-1 flex flex-col ${t.cardBg} border ${t.border} shadow-sm rounded-2xl z-10 min-h-[500px] h-auto p-0 min-w-0`}>
              <div className="p-4 md:p-5 flex flex-col flex-1 min-w-0 relative z-[45] pointer-events-auto">
                  <h3 className={`font-extrabold text-base md:text-lg mb-4 md:mb-6 border-b ${t.border} pb-3 ${t.primaryText}`}>📝 깊은 묵상 노트</h3>
                  <div className="mb-4 md:mb-6 flex flex-col"><span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase tracking-wider mb-2 flex items-center gap-1.5`}>{ReportIcon && <ReportIcon className="w-4 h-4" isDark={isDarkMode}/>} 적용 질문</span><textarea rows={1} value={currDay.qtAppQuestion || ''} onChange={e => updateDay && updateDay({qtAppQuestion: e.target.value})} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full bg-transparent resize-none outline-none text-[13px] md:text-sm font-medium ${t.textMain} note-lines h-auto overflow-hidden whitespace-pre-wrap`} placeholder="적용 질문을 적어보세요..." /></div>
                  <div className="mb-4 md:mb-6 flex flex-col"><span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase tracking-wider mb-2 flex items-center gap-1.5`}>{BibleIcon && <BibleIcon className="w-4 h-4" isDark={isDarkMode}/>} 묵상하기</span><textarea rows={1} value={currDay.qtMeditation || ''} onChange={e => updateDay && updateDay({qtMeditation: e.target.value})} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full bg-transparent resize-none outline-none text-[13px] md:text-sm font-medium ${t.textMain} note-lines h-auto overflow-hidden whitespace-pre-wrap`} placeholder="묵상 내용을 자유롭게 적어보세요..." /></div>
                  <div className="flex flex-col flex-1"><span className={`text-[10px] md:text-[11px] font-bold ${t.textSub} uppercase tracking-wider mb-2 flex items-center gap-1.5`}>{PrayingHandsIcon && <PrayingHandsIcon className={`w-4 h-4 ${t.greenText}`} isDark={isDarkMode}/>} 적용하기</span><textarea rows={1} value={currDay.qtApplication || ''} onChange={e => updateDay && updateDay({qtApplication: e.target.value})} onInput={handleAutoResize} onPointerDown={e => e.stopPropagation()} className={`w-full bg-transparent resize-none outline-none text-[13px] md:text-sm font-medium ${t.textMain} note-lines h-auto overflow-hidden min-h-full whitespace-pre-wrap`} placeholder="오늘 하루 어떻게 적용할까요?" /></div>
              </div>
          </div>
        </div>
      </CanvasEngine>
      )}
    </div>
  );
}