import React from 'react';

export default function Home({
  t, 
  isDarkMode, 
  setActiveScreen, 
  isSidebarOpen, 
  setIsSidebarOpen,
  openModal,
  bibleProgress,
  readChapsCount,
  currDay,
  readChallengeStart,
  supabase,
  MenuIcon,
  date,
  setDate,
  hasNewBoardPost,
  setHasNewBoardPost,
  HeartIcon,
  PrayingHandsIcon,
  formatVerse,
  dateHash,
  currentBgUrl,
  FireIcon,
  BibleIcon,
  updateDay,
  triggerConfetti,
  SmileFaceIcon,
  SunflowerIcon,
  NotebookIcon,
  DiaryIcon,
  ChurchIcon,
  YoutubeIcon,
  isWknd,
  ymdStr,
  praiseChannels,
  UserFaceIcon,
  authUser,
  cellData,
  MapIcon,
  // 👇 추가로 누락되었던 아이콘 짐들입니다!
  HeadphonesIcon,
  ReportIcon
}) {
  
  // 1. 계산 로직
  const startD = new Date(readChallengeStart); 
  const dDay = Math.ceil((new Date().getTime() - startD.getTime()) / 86400000) + 1;
  const streak5 = (cellData && cellData.streak5) ? cellData.streak5 : 0; 
  
  // 💡 안전장치: formatVerse가 혹시 비어있더라도 앱이 뻗지 않도록 기본값을 세팅해 줍니다.
  const safeVerse = formatVerse || { text: '오늘의 말씀을 불러오는 중입니다...', ref: '' };

  // 2. 홈 화면 UI 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} overflow-y-auto pb-[100px] hide-scrollbar animate-fade-in-up pointer-events-auto`}>
      {!supabase && ( <div className="bg-red-500 text-white text-[10px] font-bold py-1.5 px-3 text-center shadow-md z-50 sticky top-0">⚠️ SUPABASE 설정을 확인해주세요!</div> )}
      
      <div className={`flex flex-wrap items-center justify-between px-4 py-2.5 z-[45] pointer-events-auto border-b ${t.border} bg-inherit sticky top-0`}>
        <div className="flex items-center gap-2">
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className={`p-2 hover:opacity-80 transition-opacity active:opacity-50`}><MenuIcon className={`w-6 h-6 md:w-8 md:h-8 ${t.textMain}`} isDark={isDarkMode}/></button>
           <div className={`relative inline-flex items-center cursor-pointer z-30 px-1 py-1 ${t.iconDarkBg} rounded-lg`}>
              <input type="date" value={date} onChange={e=>setDate(e.target.value)} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-40" />
              <span className={`font-extrabold text-lg md:text-xl ${t.textMain} tracking-tight select-none pointer-events-none flex items-center gap-1`}>
                 {new Date(date).toLocaleDateString('ko-KR', {month:'long', day:'numeric'})} 
                 ({['일','월','화','수','목','금','토'][new Date(date).getDay()]})
              </span>
           </div>
        </div>
        <div className="flex gap-1.5 mt-2 sm:mt-0 w-full sm:w-auto justify-end">
           <button onClick={() => { setActiveScreen('board'); setHasNewBoardPost(false); }} className={`flex-1 sm:flex-none px-3 py-1.5 rounded-lg text-[11px] font-bold flex items-center justify-center gap-1 bg-[#FF2D55]/10 ${t.pinkText} shadow-sm relative hover:scale-105 transition-transform`}>
              <HeartIcon className="w-3.5 h-3.5" isDark={isDarkMode}/> 감사나눔
              {hasNewBoardPost && <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full animate-ping"></span>}
           </button>
           <button onClick={() => { setActiveScreen('board'); setHasNewBoardPost(false); }} className={`flex-1 sm:flex-none px-3 py-1.5 rounded-lg text-[11px] font-bold flex items-center justify-center gap-1 bg-green-500/10 text-green-600 dark:text-green-400 shadow-sm relative hover:scale-105 transition-transform`}>
              <PrayingHandsIcon className="w-3.5 h-3.5" isDark={isDarkMode}/> 기도요청
           </button>
        </div>
      </div>

      <div className="px-4 mt-4 mb-2">
        <div className={`relative rounded-2xl overflow-hidden shadow-sm cursor-pointer hover:opacity-90 transition-opacity min-h-[140px] flex flex-col justify-center border ${t.border} mb-6`} onClick={() => openModal('fullVerse', { text: `${safeVerse.text} ${safeVerse.ref}`, bgHash: dateHash })}>
           <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url(${currentBgUrl})` }}></div>
           <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-[1px]"></div>
           <div className="relative z-10 p-4 mx-2 my-2 rounded-xl">
             <span className="text-xs font-bold text-white/80 mb-3 flex justify-between drop-shadow-md">🔥 오늘의 말씀 카드 <span className="text-[10px] opacity-60">터치하여 크게보기 ↗</span></span>
             <span className="text-sm text-white font-bold leading-relaxed drop-shadow-md break-keep font-yeongnamnu">
                 {safeVerse.text}
                 <span className="block mt-2 text-[11px] opacity-80 font-sans">{safeVerse.ref}</span>
             </span>
           </div>
        </div>

        <div className={`${t.cardBg} rounded-2xl shadow-sm border ${t.border} overflow-hidden pointer-events-auto mt-2 mb-6 p-4`}>
           <h2 className={`text-xl font-extrabold ${t.textMain} mb-1 flex items-center gap-2`}><FireIcon className={`w-9 h-9 ${t.pinkText}`} isDark={isDarkMode} /> 영적 5종 세트</h2>
           <p className={`text-xs ${t.textSub} mb-4`}>매일의 영적 성장을 위한 필수 루틴과 말씀</p>
           <div className="flex flex-col sm:flex-row gap-3">
               <div className={`p-4 rounded-2xl border ${t.border} flex-[3] flex justify-around items-center shadow-sm bg-slate-50 dark:bg-[#2C2C2E]`}>
                  {[ 
                    { id: '감사', icon: <HeartIcon className={`w-6 h-6`} isDark={isDarkMode} /> }, 
                    { id: '성경읽기', label: '성경(맥체인)', icon: <BibleIcon className={`w-6 h-6`} isDark={isDarkMode} /> }, 
                    { id: 'QTin', icon: <FireIcon className={`w-6 h-6`} isDark={isDarkMode} /> } 
                  ].map(item => {
                    const isChecked = (currDay.checks||{})[item.id];
                    let bgClass = `bg-white dark:bg-[#1C1C1E] border ${t.border}`;
                    let iconColor = t.textSub;
                    if (isChecked) {
                        if (item.id === '성경읽기') { bgClass = 'bg-[#E3F2FD] dark:bg-[#1E3A8A] border-[#BBDEFB] dark:border-[#1565C0] shadow-md scale-110'; iconColor = 'text-[#1E88E5] dark:text-[#90CAF9]'; }
                        else if (item.id === '감사') { bgClass = 'bg-[#FCE4EC] dark:bg-[#880E4F] border-[#F8BBD0] dark:border-[#AD1457] shadow-md scale-110'; iconColor = 'text-[#D81B60] dark:text-[#F48FB1]'; }
                        else { bgClass = 'bg-[#FFF8E1] dark:bg-[#FF8F00]/20 border-[#FFECB3] dark:border-[#FF8F00]/50 shadow-md scale-110'; iconColor = 'text-[#FF8F00] dark:text-[#FFB74D]'; }
                    } else { iconColor = item.id === '감사' ? t.pinkText : item.id === '성경읽기' ? t.primaryText : t.yellowText; }
                    return (
                      <div key={item.id} onClick={() => { updateDay({ checks: { ...(currDay.checks||{}), [item.id]: !isChecked } }); if (!isChecked) triggerConfetti(); }} className="flex flex-col items-center cursor-pointer hover:-translate-y-1 transition-transform group">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${bgClass}`}>
                            <span className={isChecked ? iconColor : `opacity-40 group-hover:opacity-80 transition-opacity ${iconColor}`}>{item.icon}</span>
                        </div>
                        <span className={`text-[10px] mt-2 font-bold whitespace-nowrap ${isChecked ? t.textMain : t.textSub}`}>{item.label || item.id}</span>
                      </div>
                    );
                  })}
               </div>
               <div className={`p-4 rounded-2xl border ${t.border} flex-[2] flex justify-around items-center shadow-sm bg-[#CE93D8]/10 dark:bg-[#CE93D8]/10`}>
                  {[ 
                    { id: '기도하기', label: '(기도)', icon: <PrayingHandsIcon className={`w-6 h-6`} isDark={isDarkMode} /> }, 
                    { id: '가정예배', label: '(가정예배)', icon: <SmileFaceIcon className={`w-6 h-6`} isDark={isDarkMode} /> } 
                  ].map(item => {
                    const isChecked = (currDay.checks||{})[item.id];
                    let bgClass = `bg-white dark:bg-[#1C1C1E] border ${t.border}`;
                    let iconColor = t.purpleText;
                    if (isChecked) {
                        if (item.id === '기도하기') { bgClass = 'bg-[#E8F5E9] dark:bg-[#1B5E20] border-[#C8E6C9] dark:border-[#2E7D32] shadow-md scale-110'; iconColor = 'text-[#43A047] dark:text-[#81C784]'; }
                        else { bgClass = 'bg-[#F3E5F5] dark:bg-[#4A148C] border-[#E1BEE7] dark:border-[#6A1B9A] shadow-md scale-110'; iconColor = 'text-[#8E24AA] dark:text-[#CE93D8]'; }
                    } else { iconColor = item.id === '기도하기' ? t.greenText : t.purpleText; }
                    return (
                      <div key={item.id} onClick={() => { updateDay({ checks: { ...(currDay.checks||{}), [item.id]: !isChecked } }); if (!isChecked) triggerConfetti(); }} className="flex flex-col items-center cursor-pointer hover:-translate-y-1 transition-transform group">
                        <div className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-all ${bgClass}`}>
                            <span className={isChecked ? iconColor : `opacity-50 scale-75 group-hover:opacity-80 transition-opacity ${iconColor}`}>{item.icon}</span>
                        </div>
                        <span className={`text-[10px] mt-2 font-bold whitespace-nowrap ${isChecked ? t.textMain : t.textSub}`}>{item.label || item.id}</span>
                      </div>
                    );
                  })}
               </div>
           </div>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-5">
           <div onClick={() => setActiveScreen('fiveSetMenu')} className={`${t.cardBg} p-5 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-3 ${t.iconDarkBg} ${t.yellowText} shadow-md`}><SunflowerIcon className="w-5 h-5" isDark={isDarkMode} /></div>
              <span className={`text-[10px] md:text-xs font-bold ${t.textSub} mb-1 whitespace-nowrap`}>영적 5종 세트 관리</span><span className={`text-base md:text-lg font-black ${t.yellowText} whitespace-nowrap`}>{streak5}일 연속</span>
           </div>
           <div onClick={() => { setActiveScreen('bible'); openModal('bibleChallenge'); }} className={`${t.cardBg} p-5 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-3 ${t.iconDarkBg} ${t.primaryText} shadow-md`}><BibleIcon className="w-5 h-5" isDark={isDarkMode} /></div>
              <span className={`text-[10px] md:text-xs font-bold ${t.textSub} mb-1 whitespace-nowrap`}>통독 365 챌린지</span><span className={`text-base md:text-lg font-black ${t.primaryText} mb-2 whitespace-nowrap`}>D-{dDay > 0 ? dDay : 0}</span>
              <div className={`w-full max-w-[100px] ${t.appBg} rounded-full h-1.5 overflow-hidden shadow-inner border ${t.border}`}><div className={`bg-[#8AB4F8] h-full transition-all duration-500`} style={{width:`${bibleProgress}%`}}></div></div>
           </div>
        </div>
      </div>
      
      <div className={`w-full h-2 ${t.appBg} my-2`}></div>

      <div className="px-4 mt-4 mb-2">
         <h2 className={`text-lg md:text-xl font-extrabold ${t.textMain} mb-1 flex items-center gap-2`}><BibleIcon className={`w-6 h-6 md:w-8 md:h-8 ${t.primaryText}`} isDark={isDarkMode} /> 말씀</h2>
         <p className={`text-[11px] md:text-xs ${t.textSub} mb-4`}>오늘 내게 주시는 생명의 양식</p>
         <div className="grid grid-cols-2 gap-3 mb-6">
            <div onClick={() => setActiveScreen('qt')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
               <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-2 bg-red-50 dark:bg-red-900/20 text-red-500 shadow-md`}><SunflowerIcon className="w-5 h-5" isDark={isDarkMode} /></div><span className={`text-[12px] md:text-sm font-extrabold ${t.textMain} whitespace-nowrap`}>매일 QT</span>
            </div>
            <div onClick={() => setActiveScreen('mcheyne')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
               <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-2 bg-blue-50 dark:bg-blue-900/20 text-blue-500 shadow-md`}><NotebookIcon className="w-5 h-5" isDark={isDarkMode} /></div><span className={`text-[12px] md:text-sm font-extrabold ${t.textMain} whitespace-nowrap`}>맥체인 읽기</span>
            </div>
         </div>

         <div onClick={() => setActiveScreen('generalNote')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex items-center justify-between hover:-translate-y-1 transition-transform mb-6 group`}>
            <div className="flex items-center gap-4">
               <div className={`w-10 h-10 bg-purple-50 dark:bg-purple-900/20 shadow-md rounded-2xl flex items-center justify-center text-purple-500 group-hover:scale-110 transition-transform`}><DiaryIcon className="w-5 h-5" isDark={isDarkMode} /></div>
               <div className="flex flex-col"><span className={`text-[13px] md:text-sm font-extrabold ${t.textMain} whitespace-nowrap`}>일반 자유 노트</span><span className={`text-[10px] md:text-[11px] ${t.textSub} mt-0.5 font-bold`}>말씀을 첨부하고 마음껏 필기하세요</span></div>
            </div>
            <span className={`${t.textSub} font-bold text-xl group-hover:${t.purpleText} transition-colors mr-2`}>➔</span>
         </div>
      </div>

      <div className={`w-full h-2 ${t.appBg} my-2`}></div>

      <div className="px-4 mt-4 mb-2">
         <h2 className={`text-lg md:text-xl font-extrabold ${t.textMain} mb-1 flex items-center gap-2`}><ChurchIcon className={`w-6 h-6 md:w-8 md:h-8 ${t.greenText}`} isDark={isDarkMode} /> 예배</h2>
         <p className={`text-[11px] md:text-xs ${t.textSub} mb-4`}>주일 예배 영상 시청과 말씀 노트 기록</p>
         
         <div className="mb-4 flex justify-between items-end px-1 mt-6">
            <h3 className={`text-xs md:text-sm font-extrabold ${t.textMain} flex items-center gap-2 whitespace-nowrap`}><YoutubeIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.pinkText}`} isDark={isDarkMode} /> 매일 예배 / 설교 영상</h3>
            <span className={`text-[9px] md:text-[10px] ${t.textSub} font-bold px-2 py-1 ${t.appBg} rounded-md whitespace-nowrap border ${t.border}`}>스와이프 ↔</span>
         </div>
         <div className="flex gap-3 overflow-x-auto snap-x hide-scrollbar pb-6 px-1 mb-2">
            {[
                { title: isWknd ? '우리들교회 새벽예배' : '김양재 목사 큐티노트', url: `https://www.youtube.com/results?search_query=${isWknd ? '우리들교회+새벽예배' : '우리들교회+김양재+목사+큐티노트'}+${ymdStr}`, bg: 'https://images.unsplash.com/photo-1504052434569-70ad5836ab65?auto=format&fit=crop&w=400&q=80' },
                { title: '맥체인 듣기 (부산신성교회)', url: `https://www.youtube.com/results?search_query=부산신성교회+맥체인+성경읽기+${ymdStr}`, bg: 'https://images.unsplash.com/photo-1456513080510-7bf3a84b82f8?auto=format&fit=crop&w=400&q=80' },
                { title: '맥체인 해설 (부산신성교회)', url: `https://www.youtube.com/results?search_query=부산신성교회+맥체인+성경+해설+${ymdStr}`, bg: 'https://images.unsplash.com/photo-1455390582262-044cdead277a?auto=format&fit=crop&w=400&q=80' },
                { title: '좋은나무교회 새벽기도회', url: `https://www.youtube.com/results?search_query=김포좋은나무교회+새벽기도회+${ymdStr}`, bg: 'https://images.unsplash.com/photo-1470252649378-9c29740c9fa8?auto=format&fit=crop&w=400&q=80' },
                { title: '좋은나무교회 1분 설교', url: `https://www.youtube.com/results?search_query=김포좋은나무교회+1분설교+${ymdStr}`, bg: 'https://images.unsplash.com/photo-1548625149-fc4a29cf7092?auto=format&fit=crop&w=400&q=80' }
            ].map((link, idx) => (
               <div key={idx} onClick={() => window.open(link.url, '_blank')} className={`min-w-[120px] md:min-w-[160px] h-[160px] md:h-[200px] relative rounded-3xl overflow-hidden shadow-sm snap-center cursor-pointer hover:scale-105 transition-transform flex-shrink-0 border ${t.border}`}>
                  <img src={link.bg} alt="worship" className="absolute inset-0 w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
                  <div className="absolute bottom-0 left-0 w-full p-2 text-center"><h4 className="text-white font-black text-[10px] md:text-xs drop-shadow-md break-keep">{link.title}</h4></div>
               </div>
            ))}
         </div>

         <div className="grid grid-cols-2 gap-3 mb-6">
            <div onClick={() => setActiveScreen('sermon')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
               <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-2 bg-blue-50 dark:bg-blue-900/20 text-blue-500 shadow-md`}><ReportIcon className="w-5 h-5" isDark={isDarkMode} /></div><span className={`text-[12px] md:text-sm font-extrabold ${t.textMain} whitespace-nowrap`}>예배 노트 작성</span>
            </div>
            <div onClick={() => setActiveScreen('familySelect')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
               <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-2 bg-yellow-50 dark:bg-yellow-900/20 text-yellow-500 shadow-md`}><SmileFaceIcon className="w-5 h-5" isDark={isDarkMode} /></div><span className={`text-[12px] md:text-sm font-extrabold ${t.textMain} whitespace-nowrap`}>가정 예배 시작</span>
            </div>
         </div>
      </div>

      <div className={`w-full h-2 ${t.appBg} my-2`}></div>

      <div className="px-4 mt-4 mb-2">
         <h2 className={`text-lg md:text-xl font-extrabold ${t.textMain} mb-1 flex items-center gap-2`}><DiaryIcon className={`w-6 h-6 md:w-8 md:h-8 ${t.purpleText}`} isDark={isDarkMode} /> 묵상</h2>
         <p className={`text-[11px] md:text-xs ${t.textSub} mb-4`}>오늘의 간증, 중보기도와 찬양</p>

         <div className="grid grid-cols-2 gap-3 mb-5">
            <div onClick={() => setActiveScreen('diary')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col hover:-translate-y-1 transition-transform`}>
               <div className="flex items-center gap-2 mb-2"><DiaryIcon className={`w-5 h-5 ${t.purpleText}`} isDark={isDarkMode} /> <span className={`text-[11px] md:text-xs font-bold ${t.textMain} whitespace-nowrap`}>감사/간증 일기</span></div><span className={`text-[9px] md:text-[10px] ${t.textSub} whitespace-nowrap`}>나의 묵상과 감사 기록</span>
            </div>
            <div onClick={() => setActiveScreen('prayer')} className={`${t.cardBg} p-4 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col hover:-translate-y-1 transition-transform`}>
               <div className="flex items-center gap-2 mb-2"><PrayingHandsIcon className={`w-5 h-5 ${t.greenText}`} isDark={isDarkMode} /> <span className={`text-[11px] md:text-xs font-bold ${t.textMain} whitespace-nowrap`}>기도 보관함</span></div><span className={`text-[9px] md:text-[10px] ${t.textSub} whitespace-nowrap`}>나의 기도와 중보기도</span>
            </div>
         </div>

         <div className="mb-4 flex justify-between items-end px-1 mt-6">
            <h3 className={`text-xs md:text-sm font-extrabold ${t.textMain} flex items-center gap-2 whitespace-nowrap`}><HeadphonesIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.purpleText}`} isDark={isDarkMode} /> 유튜브 찬양 채널 모음</h3>
            <span className={`text-[9px] md:text-[10px] ${t.textSub} font-bold px-2 py-1 ${t.appBg} rounded-md whitespace-nowrap border ${t.border}`}>스와이프 ↔</span>
         </div>
         <div className="flex gap-3 overflow-x-auto snap-x hide-scrollbar pb-6 px-1">
            {praiseChannels.map((chn) => (
               <div key={chn.id} onClick={() => window.open(chn.url, '_blank')} className={`min-w-[120px] md:min-w-[160px] h-[160px] md:h-[200px] relative rounded-3xl overflow-hidden shadow-sm snap-center cursor-pointer hover:scale-105 transition-transform flex-shrink-0 border ${t.border}`}>
                  <img src={chn.bg} alt="praise" className="absolute inset-0 w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
                  <div className="absolute bottom-0 left-0 w-full p-2 text-center"><h4 className="text-white font-black text-[10px] md:text-xs drop-shadow-md break-keep">{chn.title}</h4></div>
               </div>
            ))}
         </div>
      </div>

      <div className={`w-full h-2 ${t.appBg} my-2`}></div>
      
      <div className="px-4 mt-4 mb-4">
         <h2 className={`text-lg md:text-xl font-extrabold ${t.textMain} mb-1 flex items-center gap-2`}><UserFaceIcon className={`w-6 h-6 md:w-8 md:h-8 ${t.yellowText}`} isDark={isDarkMode} /> 목장 나눔</h2>
         <p className={`text-[11px] md:text-xs ${t.textSub} mb-4`}>목장 식구들과 삶과 기도를 나누는 시간</p>
         <div onClick={() => setActiveScreen('cell')} className={`${t.cardBg} p-5 md:p-6 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex items-center justify-between hover:-translate-y-1 transition-transform group`}>
            <div className="flex items-center gap-4">
               <div className={`w-12 h-12 md:w-14 md:h-14 bg-orange-50 dark:bg-orange-900/20 rounded-2xl flex items-center justify-center text-orange-500 group-hover:scale-110 transition-transform shadow-md`}><UserFaceIcon className="w-6 h-6 md:w-7 md:h-7" isDark={isDarkMode} /></div>
               <div className="flex flex-col">
                  <span className={`text-sm md:text-base font-extrabold ${t.textMain}`}>목장 나눔 (작성/조회)</span>
                  <span className={`text-[10px] md:text-[11px] ${t.textSub} mt-1 font-bold`}>{authUser?.role === 'admin' ? '🔥 관리자 권한으로 승인/수정 가능' : '말씀/감사 나눔 제출하기'}</span>
               </div>
            </div>
            <span className={`${t.textSub} font-bold text-xl group-hover:${t.yellowText} transition-colors`}>➔</span>
         </div>
      </div>

      <div className={`w-full h-2 ${t.appBg} my-2`}></div>

      <div className="px-4 mt-4 mb-8">
         <h2 className={`text-lg md:text-xl font-extrabold ${t.textMain} mb-1 flex items-center gap-2`}><NotebookIcon className={`w-6 h-6 md:w-8 md:h-8 ${t.primaryText}`} isDark={isDarkMode} /> 성경 연구</h2>
         <p className={`text-[11px] md:text-xs ${t.textSub} mb-4`}>원어의 깊은 의미를 통해 성경을 입체적으로 묵상합니다</p>
         
         <div className="flex flex-col gap-3">
           <div onClick={() => setActiveScreen('interlinear')} className={`${t.cardBg} p-5 md:p-6 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex items-center justify-between hover:-translate-y-1 transition-transform group`}>
              <div className="flex items-center gap-4">
                 <div className={`w-12 h-12 md:w-14 md:h-14 bg-indigo-50 dark:bg-indigo-900/20 rounded-2xl flex items-center justify-center text-indigo-500 group-hover:scale-110 transition-transform shadow-md`}><NotebookIcon className="w-6 h-6 md:w-7 md:h-7" isDark={isDarkMode} /></div>
                 <div className="flex flex-col"><span className={`text-sm md:text-base font-extrabold ${t.textMain}`}>원어 성경 연구 (BETA)</span><span className={`text-[10px] md:text-[11px] ${t.textSub} mt-1 font-bold`}>히브리어 / 헬라어 원어 분해 및 사전</span></div>
              </div>
              <span className={`${t.textSub} font-bold text-xl group-hover:${t.primaryText} transition-colors`}>➔</span>
           </div>
           
           <div onClick={() => setActiveScreen('bibleWiki')} className={`${t.cardBg} p-5 md:p-6 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex items-center justify-between hover:-translate-y-1 transition-transform group`}>
              <div className="flex items-center gap-4">
                 <div className={`w-12 h-12 md:w-14 md:h-14 bg-emerald-50 dark:bg-emerald-900/20 rounded-2xl flex items-center justify-center text-emerald-500 group-hover:scale-110 transition-transform shadow-md`}><MapIcon className="w-6 h-6 md:w-7 md:h-7" isDark={isDarkMode} /></div>
                 <div className="flex flex-col"><span className={`text-sm md:text-base font-extrabold ${t.textMain}`}>성경 위키 (마인드맵 검색)</span><span className={`text-[10px] md:text-[11px] ${t.textSub} mt-1 font-bold`}>사건, 인물, 장소를 연결하는 지식 그래프</span></div>
              </div>
              <span className={`${t.textSub} font-bold text-xl group-hover:${t.primaryText} transition-colors`}>➔</span>
           </div>
         </div>
      </div>
    </div>
  );
}