import React from 'react';
import { 
  ChurchIcon, FireIcon, BibleIcon, NotebookIcon, 
  SmileFaceIcon, DiaryIcon, PrayingHandsIcon, 
  UserFaceIcon, BoardIcon, ReportIcon, MapIcon,
  SunIcon, MoonIcon, HeartIcon
} from '../utils/icons';

export default function Sidebar({ 
  t, 
  isSidebarOpen, 
  setIsSidebarOpen, 
  activeScreen, 
  setActiveScreen, 
  authUser, 
  setAuthUser,
  handleLogout,
  isDarkMode,
  setIsDarkMode
}) {
  if (!isSidebarOpen) return null;

  const menuGroups = [
    { 
      title: '주요 메뉴', 
      items: [
        { id: 'home', icon: <ChurchIcon className={`w-5 h-5 ${t.primaryText}`} />, label: '홈 화면' },
        { id: 'qt', icon: <FireIcon className={`w-5 h-5 ${t.yellowText}`} />, label: '매일 QT' },
        { id: 'fiveSetMenu', icon: <span className="text-[20px]">🔥</span>, label: '영적5종세트' }
      ]
    },
    {
      title: '성경&학습',
      items: [
        { id: 'bible', icon: <BibleIcon className={`w-5 h-5 ${t.primaryText}`} />, label: '365 성경통독' },
        { id: 'mcheyne', icon: <BibleIcon className={`w-5 h-5 ${t.primaryText}`} />, label: '맥체인 읽기' },
        { id: 'sermon', icon: <ReportIcon className="w-5 h-5 text-blue-500" />, label: '예배 노트' },
        { id: 'interlinear', icon: <NotebookIcon className="w-5 h-5 text-indigo-500" />, label: '원어성경 연구 (BETA)' },
        { id: 'bibleWiki', icon: <MapIcon className="w-5 h-5 text-emerald-500" />, label: '성경 위키 (연대표)' }
      ]
    },
    {
      title: '공동체',
      items: [
        { id: 'cell', icon: <UserFaceIcon className="w-5 h-5 text-orange-500" />, label: '목장 나눔' },
        { id: 'familySelect', icon: <SmileFaceIcon className="w-5 h-5 text-yellow-500" />, label: '가정 예배' },
        { id: 'board', icon: <BoardIcon className={`w-5 h-5 ${t.textMain}`} />, label: '함께하는 감사/기도' }
      ]
    },
    {
      title: '감사와기도',
      items: [
        { id: 'generalNote', icon: <DiaryIcon className={`w-5 h-5 ${t.purpleText}`} />, label: '나의 자유 노트' },
        { id: 'diary', icon: <HeartIcon className={`w-5 h-5 ${t.pinkText}`} />, label: '감사/간증 일기' },
        { id: 'prayer', icon: <PrayingHandsIcon className={`w-5 h-5 ${t.greenText}`} />, label: '기도 보관함' }
      ]
    }
  ];

  return (
    <>
      {/* 모바일 백드롭 */}
      {window.innerWidth < 768 && (
        <div 
          onClick={() => setIsSidebarOpen(false)} 
          className="fixed inset-0 bg-black/40 backdrop-blur-sm z-[140] md:hidden pointer-events-auto"
        />
      )}

      {/* 사이드바 본체 */}
      <div className={`fixed inset-y-0 left-0 h-full border-r ${t.border} ${t.cardBg} z-[150] md:relative shadow-2xl md:shadow-none transition-[width,transform] duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0 w-[80vw] max-w-[300px]' : '-translate-x-full w-0 overflow-hidden border-none'}`}>
        <div className="w-[80vw] max-w-[300px] flex flex-col h-full bg-inherit">
          
          {/* 상단 프로필 및 로고 영역 (컴팩트하게 수정됨) */}
          <div className={`px-4 py-3.5 flex flex-col items-center justify-center border-b ${t.border} shrink-0 relative`}>
             <button onClick={() => setIsSidebarOpen(false)} className={`absolute top-2.5 right-3 text-xl font-light hover:text-[#FF2D55] p-1 md:hidden ${t.textMain}`}>✕</button>
             <div className="flex items-center gap-2 mb-1">
                <img src="/sec/image2.png" alt="좋은나무교회" className="max-h-10 md:max-h-12 w-auto object-contain drop-shadow-sm" />
             </div>
             <div className="text-center">
                <span className={`block font-black text-sm md:text-base ${t.textMain}`}>
                   {authUser?.name?.length > 2 ? authUser.name.substring(1) : (authUser?.name || '성도')}님 <span className={`font-bold text-xs md:text-sm ${t.primaryText}`}>축복합니다!</span>
                </span>
             </div>
          </div>

          {/* 카테고리별 메뉴 */}
          <div className="flex-1 overflow-y-auto px-3 py-3 space-y-3 hide-scrollbar bg-inherit pointer-events-auto">
             {menuGroups.map((group, gIdx) => (
               <div key={gIdx} className="mb-1">
                  <h4 className={`text-[10px] font-extrabold ${t.textSub} mb-1 ml-2 uppercase tracking-wider`}>{group.title}</h4>
                  <div className="space-y-0.5">
                    {group.items.map(m => (
                      <button 
                        key={m.id} 
                        onClick={() => { setActiveScreen(m.id); if (window.innerWidth < 768) setIsSidebarOpen(false); }} 
                        className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl font-bold text-[13px] transition-all ${activeScreen === m.id ? `bg-blue-500 text-white dark:bg-blue-900/30 dark:text-blue-400 shadow-sm` : `${t.textMain} hover:bg-slate-100 dark:hover:bg-[#2C2C2E]`}`}
                      >
                        {m.icon} <span>{m.label}</span>
                      </button>
                    ))}
                  </div>
               </div>
             ))}
          </div>

          {/* 하단 영역: 테마 토글 및 로그아웃 */}
          <div className={`p-3 border-t ${t.border} flex flex-col gap-2.5 mt-auto shrink-0 bg-inherit`}>
            {setIsDarkMode && (
              <div className="flex items-center justify-between px-2">
                <span className={`text-xs font-bold ${t.textMain}`}>화면 테마</span>
                <div 
                  onClick={() => setIsDarkMode(!isDarkMode)}
                  className={`w-12 h-7 flex items-center rounded-full p-1 cursor-pointer transition-colors duration-300 ${isDarkMode ? 'bg-blue-600' : 'bg-gray-300'}`}
                >
                  <div 
                    className={`w-5 h-5 rounded-full bg-white shadow-md transform transition-transform duration-300 flex items-center justify-center text-[10px] ${isDarkMode ? 'translate-x-5' : 'translate-x-0'}`}
                  >
                    {isDarkMode ? '🌙' : '☀️'}
                  </div>
                </div>
              </div>
            )}

            <button 
              onClick={() => { 
                if(window.confirm('로그아웃 하시겠습니까?')){ 
                  if (handleLogout) handleLogout();
                  else if (setAuthUser) setAuthUser(null); 
                  setActiveScreen('login'); 
                  setIsSidebarOpen(false);
                } 
              }} 
              className="w-full py-2 bg-red-500/10 hover:bg-red-500/20 text-red-500 font-bold text-xs rounded-xl transition-colors text-center"
            >
              로그아웃
            </button>
          </div>

        </div>
      </div>
    </>
  );
}