import React from 'react';

export default function FiveSetMenu({
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  HeartIcon,
  BibleIcon,
  FireIcon,
  PrayingHandsIcon,
  SmileFaceIcon
}) {

  // 🚨 [디버깅 X-ray] 어떤 컴포넌트가 안 넘어왔는지 화면에 띄워줍니다!
  if (!SubPageHeader) return <div className="p-10 text-lg font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;
  if (!HeartIcon) return <div className="p-10 text-lg font-bold text-red-500">❌ App.js에서 HeartIcon이 넘어오지 않았습니다!</div>;
  if (!BibleIcon) return <div className="p-10 text-lg font-bold text-red-500">❌ App.js에서 BibleIcon이 넘어오지 않았습니다!</div>;
  if (!FireIcon) return <div className="p-10 text-lg font-bold text-red-500">❌ App.js에서 FireIcon이 넘어오지 않았습니다!</div>;
  if (!PrayingHandsIcon) return <div className="p-10 text-lg font-bold text-red-500">❌ App.js에서 PrayingHandsIcon이 넘어오지 않았습니다!</div>;
  if (!SmileFaceIcon) return <div className="p-10 text-lg font-bold text-red-500">❌ App.js에서 SmileFaceIcon이 넘어오지 않았습니다!</div>;

  const menuItems = [
    { id: 'diary', title: '감 (감사/간증 일기)', icon: <HeartIcon className={`w-6 h-6 ${t.pinkText}`} isDark={isDarkMode} />, screen: 'diary' },
    { id: 'mcheyne', title: '성 (맥체인 성경읽기)', icon: <BibleIcon className={`w-6 h-6 ${t.primaryText}`} isDark={isDarkMode} />, screen: 'mcheyne' },
    { id: 'qt', title: '크 (매일 QT)', icon: <FireIcon className={`w-6 h-6 ${t.yellowText}`} isDark={isDarkMode} />, screen: 'qt' },
    { id: 'prayer', title: '기 (기도 보관함)', icon: <PrayingHandsIcon className={`w-6 h-6 ${t.greenText}`} isDark={isDarkMode} />, screen: 'prayer' },
    { id: 'familySelect', title: '가 (가정예배)', icon: <SmileFaceIcon className={`w-6 h-6 ${t.purpleText}`} isDark={isDarkMode} />, screen: 'familySelect' },
  ];

  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
       <SubPageHeader title="영적 5종 세트" onBack={() => setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
       <div className="flex-1 overflow-y-auto p-5 pb-40 space-y-4">
          <div className="px-2 py-3"><h2 className={`text-2xl font-black ${t.textMain}`}>성도님, 어떤 걸 하시겠어요? 😊</h2></div>
          {menuItems.map(item => (
             <div key={item.id} onClick={() => setActiveScreen(item.screen)} className={`${t.cardBg} p-5 rounded-2xl border ${t.border} shadow-sm cursor-pointer hover:-translate-y-1 transition-transform flex items-center justify-between`}>
                <div className="flex items-center gap-4">
                   <div className={`w-12 h-12 rounded-2xl ${t.appBg} border ${t.border} shadow-sm flex items-center justify-center`}>{item.icon}</div>
                   <span className={`text-sm md:text-base font-bold ${t.textMain}`}>{item.title}</span>
                </div>
                <span className={`${t.textSub} font-bold text-xl`}>→</span>
             </div>
          ))}
       </div>
    </div>
  );
}