import React, { useRef, useEffect } from 'react';

export default function RichTextEditor({ value, onChange, placeholder, t, isSp, bibles }) {
    const editorRef = useRef(null);
    useEffect(() => { 
    const s = value || ''; 
    // 💡 사용자가 포커스하여 타이핑 중이 아닐 때만 내용 동기화
    if (editorRef.current && document.activeElement !== editorRef.current) {
        if (editorRef.current.innerHTML !== s) {
            editorRef.current.innerHTML = s; 
        }
    }
}, [value]);
    const handleInput = () => { if (editorRef.current) onChange(editorRef.current.innerHTML); };
    const exec = (cmd, val = null) => { document.execCommand(cmd, false, val); editorRef.current.focus(); handleInput(); };
    
    return (
        <div className={`flex flex-col border rounded-2xl overflow-hidden w-full ${isSp ? 'bg-white/90 border-white/40' : `${t.appBg} ${t.border}`} shadow-inner min-h-[300px] h-full`}>
            <div className={`flex flex-wrap gap-1 p-2 border-b ${isSp ? 'border-white/40 bg-white/50' : `${t.border} ${t.cardBg}`} items-center sticky top-0 z-10`}>
                <button onClick={()=>exec('bold')} className={`px-2 py-1 font-extrabold rounded ${t.textMain} hover:bg-black/5 text-sm`}>B</button>
                <button onClick={()=>exec('underline')} className={`px-2 py-1 underline font-bold rounded ${t.textMain} hover:bg-black/5 text-sm`}>U</button>
                <select onChange={(e)=>exec('fontSize', e.target.value)} className={`px-2 py-1 text-sm font-bold rounded border outline-none ${t.inputBg} ${t.textMain}`}><option value="3">본문</option><option value="6">제목</option></select>
            </div>
            <div ref={editorRef} contentEditable={true} onInput={handleInput} className={`p-5 flex-1 outline-none text-[15px] overflow-y-auto ${isSp?'text-slate-800':t.textMain} break-words note-lines`} placeholder={placeholder} style={{ minHeight: '300px' }} />
        </div>
    );
}