import React from 'react';

export default function Board({
  // 💡 기본 짐 (UI, 네비게이션)
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 상태 및 데이터 짐
  mLocal = {},
  setMLocal,
  authUser = {},
  boardPosts = [],
  setBoardPosts,
  newPostText,
  setNewPostText,
  isLoadingPosts,
  
  // 💡 외부 서비스 및 함수 짐
  supabase,
  fetchPosts,
  getArr
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  // 1. 탭 상태 관리
  const currentBoardTab = mLocal?.boardTab || 'thanks';
  const setBoardTab = (tab) => setMLocal && setMLocal({...mLocal, boardTab: tab});

  // 2. 게시글 액션 처리 함수 (좋아요, 응답, 수정)
  const handleAction = async (post, actionType, newText = '') => {
     try {
        let parsed = {};
        try { parsed = JSON.parse(post.content); } catch(e) { parsed = { text: post.content }; }
        if (actionType === 'amen') parsed.likes = (parsed.likes || 0) + 1;
        if (actionType === 'answer') parsed.status = 'answered';
        if (actionType === 'edit') parsed.text = newText;
        const newContent = JSON.stringify(parsed);
        if (supabase) await supabase.from('test_board').update({ content: newContent }).eq('id', post.id);
        if (setBoardPosts) setBoardPosts(posts => getArr(posts).map(p => p.id === post.id ? {...p, content: newContent} : p));
     } catch(e) {}
  };

  // 3. 데이터 필터링 로직
  const validPosts = getArr(boardPosts);
  const filteredPosts = validPosts.filter(p => { try { const data = JSON.parse(p.content); return data.type === currentBoardTab; } catch(e) { return false; } });
  const activePrayers = filteredPosts.filter(p => { try { return JSON.parse(p.content).status !== 'answered'; } catch(e) { return true; } });
  const answeredPrayers = filteredPosts.filter(p => { try { return JSON.parse(p.content).status === 'answered'; } catch(e) { return false; } });

  // 4. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
      <SubPageHeader title="함께하는 감사/기도" onBack={() => setActiveScreen('home')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
      
      <div className={`flex ${t.cardBg} border-b ${t.border} shrink-0 px-4 pt-2 shadow-sm`}>
          <button onClick={() => setBoardTab('thanks')} className={`flex-1 pb-3 text-[13px] md:text-[14px] font-semibold transition-all ${currentBoardTab==='thanks' ? `${t.textMain} border-b-2 border-black dark:border-white` : t.textSub}`}>🌼 함께하는 감사</button>
          <button onClick={() => setBoardTab('prayer')} className={`flex-1 pb-3 text-[13px] md:text-[14px] font-semibold transition-all ${currentBoardTab==='prayer' ? `${t.textMain} border-b-2 border-black dark:border-white` : t.textSub}`}>🛐 오늘 필요한 기도</button>
      </div>
      
      <div className="flex-1 overflow-y-auto p-4 sm:p-6 pb-40 space-y-6">
        <div className={`${t.cardBg} p-5 rounded-2xl shadow-sm border ${t.border}`}>
           <textarea value={newPostText || ''} onChange={e=>setNewPostText && setNewPostText(e.target.value)} className={`w-full p-4 rounded-xl ${t.inputBg} ${t.textMain} border-none outline-none resize-none h-24 text-[13px] md:text-[14px]`} placeholder={currentBoardTab==='thanks' ? "우리 모두가 함께 감사할 수 있도록 적어주세요..." : "우리 모두가 함께 기도할 수 있도록 적어주세요..."} />
           <button onClick={async () => {
               if (!supabase) return alert("Supabase 연결 설정이 필요합니다."); 
               if (!newPostText || !newPostText.trim()) return alert("내용을 입력해주세요."); 
               const payload = JSON.stringify({ type: currentBoardTab, text: newPostText, likes: 0, author: authUser?.name || '익명', status: 'praying' });
               const { error } = await supabase.from('test_board').insert([{ content: payload }]); 
               if (error) alert("오류 발생: " + error.message); 
               else { if(setNewPostText) setNewPostText(''); if(fetchPosts) fetchPosts(); } 
           }} className={`w-full mt-3 h-12 font-semibold rounded-xl transition-transform active:scale-[0.98] text-[13px] md:text-[14px] ${isDarkMode ? 'bg-white text-black' : 'bg-[#1D1D1F] text-white'}`}>등록하기</button>
        </div>
        
        <div className="space-y-4">
          {isLoadingPosts ? <div className={`text-center py-10 ${t.textSub}`}>불러오는 중...</div> :
           (currentBoardTab === 'thanks' ? filteredPosts : activePrayers).length === 0 ? <div className={`text-center py-10 ${t.textSub}`}>아직 등록된 글이 없습니다.</div> :
           (currentBoardTab === 'thanks' ? filteredPosts : activePrayers).map(post => {
            let data = { text: '', likes: 0, author: '익명' };
            try { data = JSON.parse(post.content); } catch(e) {}
            return currentBoardTab === 'thanks' ? (
             <div key={post.id} className={`${t.cardBg} p-4 rounded-2xl shadow-sm border ${t.border}`}>
                <div className="flex justify-between items-center mb-2"><span className={`text-[11px] md:text-[12px] font-bold ${t.textMain}`}>👤 {data.author}</span><span className={`text-[9px] md:text-[10px] ${t.textSub}`}>{new Date(post.created_at).toLocaleString()}</span></div>
                <p className={`text-[13px] md:text-[14px] ${t.textMain} leading-relaxed whitespace-pre-wrap mb-4`}>{data.text}</p>
                <div className={`flex justify-between items-center border-t ${t.border} pt-2`}>
                    <button onClick={() => { const edited = window.prompt("수정:", data.text); if (edited) handleAction(post, 'edit', edited); }} className={`text-[10px] md:text-[11px] ${t.textSub} px-2 py-1`}>수정</button>
                    <button onClick={() => handleAction(post, 'amen')} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[11px] md:text-[12px] font-bold bg-pink-50 dark:bg-pink-900/20 ${t.pinkText} transition-colors`}>🙌 할렐루야 <span className="bg-white/60 dark:bg-black/20 px-1.5 rounded">{data.likes || 0}</span></button>
                </div>
             </div>
            ) : (
             <div key={post.id} className="flex relative shadow-sm group">
                <div className={`flex-1 ${t.cardBg} p-4 rounded-l-2xl border-y border-l ${t.border} flex flex-col justify-between`}>
                    <div>
                        <div className="flex justify-between items-center mb-2"><span className={`text-[11px] md:text-[12px] font-bold ${t.textMain}`}>👤 {data.author}</span><div className="flex items-center gap-2"><button onClick={() => { const edited = window.prompt("기도제목 수정:", data.text); if (edited) handleAction(post, 'edit', edited); }} className={`text-[10px] md:text-[11px] ${t.textSub} px-1.5 py-0.5 hover:${t.textMain}`}>수정</button><span className={`text-[9px] md:text-[10px] ${t.textSub}`}>{new Date(post.created_at).toLocaleDateString()}</span></div></div>
                        <p className={`text-[13px] md:text-[14px] ${t.textMain} leading-relaxed whitespace-pre-wrap mb-4`}>{data.text}</p>
                    </div>
                    <div className="flex justify-start"><button onClick={() => handleAction(post, 'amen')} className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] md:text-[11px] font-bold bg-blue-50 dark:bg-blue-900/20 ${t.primaryText} transition-colors`}>🙏 기도합니다 <span className="bg-white/60 dark:bg-black/20 px-1.5 rounded">{data.likes || 0}</span></button></div>
                </div>
                <button onClick={() => { if(window.confirm('기도가 응답되었나요? 응답 리스트로 이동합니다.')) handleAction(post, 'answer') }} className="w-12 bg-green-500 text-white rounded-r-2xl flex flex-col items-center justify-center text-[12px] font-black leading-tight hover:opacity-90 transition-colors active:scale-95 origin-right border-y border-r border-green-600"><span>응</span><span className="mt-1">답</span></button>
             </div>
            );
          })}
        </div>
        
        {currentBoardTab === 'prayer' && answeredPrayers.length > 0 && (
          <div className={`mt-8 pt-6 border-t-2 border-dashed ${t.border}`}>
              <h4 className={`text-[12px] md:text-[13px] font-extrabold ${t.greenText} mb-4 px-2 flex items-center gap-1`}>✨ 주님이 응답하신 기도</h4>
              <div className="space-y-3">
                  {answeredPrayers.map(post => {
                      let data = { text: '', author: '익명' }; try { data = JSON.parse(post.content); } catch(e) {}
                      return (
                          <div key={post.id} className={`bg-green-50/50 dark:bg-green-900/10 p-4 rounded-xl border border-green-100 dark:border-green-900/30`}>
                             <div className="flex justify-between items-center mb-1"><span className={`text-[10px] md:text-[11px] font-bold ${t.greenText}`}>👤 {data.author}</span></div>
                             <p className={`text-[12px] md:text-[13px] ${t.textSub} line-through decoration-green-400/50`}>{data.text}</p>
                          </div>
                      )
                  })}
              </div>
          </div>
        )}
      </div>
    </div>
  );
}