import React from 'react';
import RichTextEditor from '../components/RichTextEditor'; // 💡 RichTextEditor 직접 임포트

export default function Sermon({
  // 💡 기본 필수 짐들
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 UI 코드 분석 후 추가된 짐들 (엄청 많습니다! 📦)
  date,
  isGisangogi,
  authUser,
  renderToolbar,
  sermonEditorRef,
  handleStickerAdd,
  handleMemoAdd,
  handleFileUpload,
  CanvasEngine,
  tool,
  setTool,
  color,
  setColor,
  size,
  setSize,
  StickerLayer,
  currDay,
  updateDay,
  onPtrDown,
  openModal,
  downloadSermonWord,
  gisangogiUrl,
  setGisangogiUrl,
  findBibleText,
  HeartIcon,
  getArr,
  ReportIcon,
  toggleAiDetect,
  isAiDetecting,
  MicIcon,
  YoutubeIcon,
  isWknd,
  ymdStr,
  extractVideoId,
  handleUpdateSharedQt,
  globalSharedQt,
  setDailyData,
  bibles
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;
  if (!CanvasEngine) return <div className="p-10 font-bold text-red-500">❌ App.js에서 CanvasEngine이 넘어오지 않았습니다!</div>;

  // 1. 계산 로직 (기상오기 매핑 포함)
  const safeDay = currDay || {};
  const isSp = isGisangogi ? isGisangogi(date) : false;
  const isAdmin = authUser?.role === 'admin';

  // 2. 화면 렌더링
  return (
    <div className={`flex-1 flex flex-col h-full ${isSp ? 'bg-[#9CB4D8] text-white' : t.pageBg} animate-fade-in-up relative`}>
      {/* 상단 헤더 */}
      <SubPageHeader title="예배 노트" onBack={()=>setActiveScreen('home')} t={t} isSp={isSp} spTitle="✨ 기상오기" spDesc="(기적이 상식이 되는 5일의 기도)" toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
      
      {/* 툴바 */}
      {renderToolbar && renderToolbar(sermonEditorRef, true, handleStickerAdd, handleMemoAdd, handleFileUpload)}
      
      {/* 캔버스 엔진 (그림 그리기 기능) */}
      {CanvasEngine && (
      <CanvasEngine key={`sermon_${date}`} saveKey={`sermon_${date}`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={safeDay.memos} stickers={safeDay.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} /> : null}>
        <div className="p-4 sm:p-6 flex flex-col md:flex-row gap-5 md:gap-8 pb-40 md:pb-20 items-stretch h-full overflow-y-auto">
          <div className="flex-1 flex flex-col gap-5 min-w-0">
            
            {/* 날짜 및 상단 버튼 */}
            <div className="flex justify-between items-center mb-1 flex-wrap gap-2 relative z-[45] pointer-events-auto">
                <span className={`text-[13px] md:text-sm font-extrabold ${t.textMain}`}>{date}</span>
                <div className="flex gap-1.5 md:gap-2 ignore-draw">
                  <button onClick={() => openModal && openModal('sermonList')} className={`px-2.5 md:px-3 py-1.5 rounded-lg text-[10px] md:text-xs font-bold shadow-sm ${t.primaryText} bg-[#8AB4F8]/10 hover:opacity-90 whitespace-nowrap`}>📋 전체 목록</button>
                  <button onClick={downloadSermonWord} className={`relative z-50 pointer-events-auto px-2.5 md:px-3 py-1.5 rounded-lg text-[10px] md:text-xs font-bold shadow-sm ${t.iconDarkBg} ${t.textMain} hover:opacity-90 whitespace-nowrap`}>💾 Word 저장</button>
                </div>
            </div>
            
            {/* 특별 기간(기상오기) 유튜브 영상 */}
            {isSp && (
                <div className="mb-4 relative z-[45] pointer-events-auto">
                  {isAdmin && (
                      <div className="mb-2 flex gap-2 items-center bg-blue-50 dark:bg-blue-900/20 p-2 rounded-lg border border-blue-200">
                        <span className="text-[10px] font-bold text-blue-600">관리자 영상수정:</span>
                        <input type="text" value={gisangogiUrl || ''} onChange={(e) => setGisangogiUrl && setGisangogiUrl(e.target.value)} onPointerDown={e => e.stopPropagation()} className="flex-1 border text-xs p-1 rounded outline-none text-black" placeholder="유튜브 링크 입력" />
                      </div>
                  )}
                  <div className="w-full aspect-video bg-black rounded-xl overflow-hidden shadow-md relative">
                      <iframe width="100%" height="100%" src={(gisangogiUrl || '').replace('youtu.be/', 'www.youtube.com/embed/').split('?')[0] + "?autoplay=1&mute=0"} title="기상오기" frameBorder="0" allow="autoplay; encrypted-media" allowFullScreen className="absolute inset-0 w-full h-full"></iframe>
                  </div>
                </div>
            )}

            {/* 설교 제목, 설교자, 본문 입력 */}
            <div className={`${isSp ? 'bg-white/90 shadow-xl text-[#1D1D1F]' : `${t.cardBg} border ${t.border} shadow-sm`} p-4 md:p-5 rounded-2xl flex flex-col gap-3 md:gap-4 relative z-[45] pointer-events-auto`}>
              <div className="flex flex-col sm:flex-row gap-3 md:gap-4">
                  <div className="flex-1 flex flex-col gap-1 md:gap-1.5"><span className="text-[10px] md:text-xs font-bold uppercase text-inherit">설교 제목</span><input type="text" value={safeDay.sermonTitle||''} onChange={e=>updateDay({sermonTitle:e.target.value})} onPointerDown={e => e.stopPropagation()} className={`w-full h-10 md:h-12 px-3 md:px-4 rounded-xl text-[12px] md:text-sm font-bold border outline-none ${isSp ? 'bg-black/5 text-[#1D1D1F] border-transparent' : `${t.inputBg} ${t.textMain}`}`} /></div>
                  <div className="flex-1 flex flex-col gap-1 md:gap-1.5"><span className={`text-[10px] md:text-xs font-bold uppercase ${isSp ? 'text-blue-600' : t.primaryText}`}>설교자</span><input type="text" value={safeDay.sermonPreacher||''} onChange={e=>updateDay({sermonPreacher:e.target.value})} onPointerDown={e => e.stopPropagation()} className={`w-full h-10 md:h-12 px-3 md:px-4 rounded-xl text-[12px] md:text-sm font-bold border outline-none ${isSp ? 'bg-black/5 text-[#1D1D1F] border-transparent' : `${t.inputBg} ${t.textMain}`}`} /></div>
              </div>
              <div className="flex flex-col gap-1 md:gap-1.5"><span className="text-[10px] md:text-xs font-bold uppercase text-inherit">본문</span><div className="flex gap-1.5 md:gap-2"><input type="text" value={safeDay.sermonReference||''} onChange={e=>updateDay({sermonReference:e.target.value})} onPointerDown={e => e.stopPropagation()} className={`flex-1 h-10 md:h-12 px-3 md:px-4 rounded-xl text-[12px] md:text-sm font-bold border outline-none ${isSp ? 'bg-black/5 text-[#1D1D1F] border-transparent' : `${t.inputBg} ${t.textMain}`}`} /><button onClick={()=>findBibleText && findBibleText(safeDay.sermonReference)} className={`h-10 md:h-12 px-4 md:px-5 bg-blue-500 hover:opacity-80 text-white dark:text-[#1D1D1F] rounded-xl text-[11px] md:text-sm font-bold shadow-sm transition-colors ignore-draw whitespace-nowrap`}>찾기</button></div></div>
            </div>
            
            {/* 나의 감사 선포 */}
            <div className={`${isSp ? 'bg-white/90 shadow-xl text-[#1D1D1F]' : `${t.cardBg} border ${t.border} shadow-sm`} p-4 md:p-5 rounded-2xl cursor-pointer hover:-translate-y-1 transition-transform relative z-[45] pointer-events-auto`} onClick={()=>openModal && openModal('thanksDeclaration', safeDay, updateDay)}>
              <h3 className={`font-bold text-[13px] md:text-sm mb-3 ${isSp ? 'text-[#FF2D55]' : t.pinkText} flex items-center gap-2`}>{HeartIcon && <HeartIcon className="w-4 h-4 md:w-5 md:h-5" isDark={isDarkMode} />} 나의 감사 선포 ↗</h3>
              <div className="flex flex-col gap-2">{(getArr ? getArr(safeDay.thanksDeclarations, ['','']) : []).map((q, i) => <div key={i} className={`p-2.5 md:p-3 rounded-lg border ${isSp?'bg-white/50 border-[#E5E5EA]':`${t.appBg} ${t.textMain} ${t.border}`}`}><span className={`${isSp ? 'text-[#FF2D55]' : t.pinkText} font-bold mr-2 text-[11px] md:text-xs`}>{i+1}.</span><span className="text-[12px] md:text-sm">{q||<span className="opacity-50 text-[#8E8E93]">기록하세요.</span>}</span></div>)}</div>
            </div>
            
            {/* 나의 적용 질문 */}
            <div className={`${isSp ? 'bg-white/90 shadow-xl text-[#1D1D1F]' : `${t.cardBg} border ${t.border} shadow-sm`} p-4 md:p-5 rounded-2xl cursor-pointer hover:-translate-y-1 transition-transform relative z-[45] pointer-events-auto`} onClick={()=>openModal && openModal('applyQuestion', safeDay, updateDay)}>
              <div className="flex justify-between items-center mb-3">
                  <h3 className={`font-bold text-[13px] md:text-sm ${isSp ? 'text-[#007AFF]' : t.primaryText} flex items-center gap-2`}>{ReportIcon && <ReportIcon className="w-4 h-4 md:w-5 md:h-5" isDark={isDarkMode} />} 나의 적용 질문 ↗</h3>
                  <button onClick={(e) => { e.stopPropagation(); toggleAiDetect && toggleAiDetect(); }} className={`text-[10px] md:text-[11px] font-bold px-2 py-1 rounded-md shadow-sm border transition-colors ${isAiDetecting ? `bg-[#F48FB1]/10 ${t.pinkText} border-[#F48FB1]/30 animate-pulse` : `bg-[#8AB4F8]/10 text-blue-500 border-[#8AB4F8]/20 hover:opacity-80`}`}>{MicIcon && <MicIcon className="w-3 h-3 inline-block mr-1" isDark={isDarkMode}/>} {isAiDetecting ? '🔴 음성 듣는중...' : '🤖 STT 음성인식'}</button>
              </div>
              <div className="flex flex-col gap-2">{(getArr && getArr(safeDay.applyQuestions).length>0) ? getArr(safeDay.applyQuestions).map((q, i) => <div key={i} className={`p-2.5 md:p-3 rounded-lg border flex gap-2 ${(q||'').startsWith('🎙️')?'bg-[#CE93D8]/5 border-[#CE93D8]/20 text-[#CE93D8]':isSp?'bg-white/50 border-[#E5E5EA]':`${t.appBg} ${t.textMain} ${t.border}`}`}><span className={`${isSp ? 'text-[#007AFF]' : t.primaryText} font-bold text-[11px] md:text-xs`}>{i+1}.</span><span className="text-[12px] md:text-sm whitespace-pre-wrap">{q}</span></div>) : <div className={`text-center py-3 border border-dashed rounded-lg text-[11px] md:text-xs ${isSp?'text-[#8E8E93] border-[#E5E5EA]':`${t.textSub} ${t.border}`}`}>기록이 없습니다.</div>}</div>
            </div>

            {/* 일반 기간(기상오기 아닐 때) 유튜브 링크 */}
            {!isSp && (
            <div className={`${t.cardBg} border ${t.border} shadow-sm p-4 md:p-5 rounded-2xl flex flex-col gap-3 md:gap-4 relative z-[45] pointer-events-auto ignore-draw`}>
                <div className="flex justify-between items-center">
                  <h3 className={`font-bold ${t.textMain} text-[13px] md:text-sm flex items-center gap-2 whitespace-nowrap`}>{YoutubeIcon && <YoutubeIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.pinkText}`} isDark={isDarkMode}/>} 예배 / 설교 영상 시청</h3>
                  <a href={`https://www.youtube.com/results?search_query=${isWknd ? '우리들교회+주일예배' : '우리들교회+새벽예배'}+${ymdStr}`} target="_blank" rel="noreferrer" className={`text-[9px] md:text-[10px] bg-red-50 dark:bg-red-900/20 text-red-500 px-2 py-1 rounded font-bold shadow-sm`}>유튜브 검색 ↗</a>
                </div>
                <div className="flex gap-1.5 md:gap-2">
                    <input type="text" placeholder="영상 링크 붙여넣기..." value={safeDay.sermonVideoUrl || ''} onChange={(e) => { const url = e.target.value; const vId = extractVideoId ? extractVideoId(url) : null; updateDay({ sermonVideoUrl: url, sermonVideoId: vId !== null ? vId : '' }); }} onPointerDown={e => e.stopPropagation()} className={`flex-1 h-8 md:h-10 px-2 md:px-3 rounded-lg text-[10px] md:text-xs font-bold border outline-none ${t.inputBg} ${t.textMain}`} />
                    <button onClick={() => { if(!safeDay.sermonVideoId) return alert("먼저 올바른 유튜브 링크를 넣어주세요."); handleUpdateSharedQt && handleUpdateSharedQt(date, 'sermon', safeDay.sermonVideoId); alert("공유되었습니다!"); }} className={`bg-[#F48FB1] text-white dark:text-[#1D1D1F] px-2.5 md:px-3 py-1 rounded-lg text-[10px] md:text-xs font-bold shadow-sm hover:opacity-90 transition-colors shrink-0`}>앱 전체 공유</button>
                </div>
                <div className={`w-full aspect-video bg-black rounded-xl overflow-hidden shadow-sm relative border ${t.border}`}>
                  {((globalSharedQt && globalSharedQt[date]?.sermon) || safeDay.sermonVideoId) ? <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${globalSharedQt[date]?.sermon || safeDay.sermonVideoId}?rel=0`} title="Sermon Video" frameBorder="0" allowFullScreen className="absolute inset-0 w-full h-full"></iframe> : <div className="absolute inset-0 flex flex-col items-center justify-center text-[#8E8E93] text-[10px] md:text-xs gap-2">{YoutubeIcon && <YoutubeIcon className="w-6 h-6 md:w-8 md:h-8 opacity-40" isDark={isDarkMode}/>}영상을 검색해 링크를 넣으면 모두와 공유됩니다.</div>}
                </div>
            </div>
            )}
          </div>
          
          {/* 리치 텍스트 에디터 영역 (성경 구절 자동 타이핑 지원) */}
          <div className={`flex-1 flex flex-col rounded-2xl overflow-hidden min-h-[500px] border ${t.border} shadow-sm min-w-0 relative z-[45] pointer-events-auto`}>
              <div className={`p-3 border-b ${t.border} ${isSp?'bg-white/80 border-[#E5E5EA]':t.appBg} flex justify-between items-center z-10`}>
                <span className={`text-[11px] md:text-xs font-bold ml-2 whitespace-nowrap ${isSp ? 'text-black' : ''}`}>📝 스마트 말씀 노트</span>
                <button onClick={(e) => {
                    const btn = e.currentTarget; const SR = window.SpeechRecognition || window.webkitSpeechRecognition; if(!SR) return alert("마이크 미지원 브라우저입니다.");
                    if(btn.dataset.recording === 'true') { btn.dataset.recording = 'false'; window.sermonRec?.stop(); btn.innerHTML = '🎤 음성입력'; btn.classList.remove('animate-pulse','text-[#FF2D55]'); return; }
                    btn.dataset.recording = 'true'; btn.innerHTML = '🔴 무제한 듣는중...'; btn.classList.add('animate-pulse','text-[#FF2D55]');
                    const startRec = () => { const rec = new SR(); rec.lang = 'ko-KR'; rec.continuous = true; window.sermonRec = rec; rec.onend = () => { if (btn.dataset.recording === 'true') { setTimeout(() => { try { startRec(); } catch(err){} }, 300); } else { btn.innerHTML = '🎤 음성입력'; btn.classList.remove('animate-pulse','text-[#FF2D55]'); } }; rec.onresult = (ev) => { let final = ''; for (let i = ev.resultIndex; i < ev.results.length; ++i) { if (ev.results[i].isFinal) final += ev.results[i][0].transcript + ' '; } if(final) { setDailyData && setDailyData(prev => { const d = prev[date] || {}; return { ...prev, [date]: { ...d, sermonNotes: (d.sermonNotes || '') + final } }; }); } }; rec.start(); }; startRec();
                }} className={`text-[9px] md:text-[10px] font-bold bg-blue-500/10 text-blue-600 px-2 py-1 rounded-md shadow-sm z-10 hover:opacity-80 ignore-draw transition-colors whitespace-nowrap`}>🎤 음성입력</button>
              </div>
              <div className={`flex-1 ${isSp?'bg-white/60':t.cardBg} relative z-0`}>
                <RichTextEditor ref={sermonEditorRef} value={safeDay.sermonNotes} onChange={(val) => updateDay({sermonNotes: val})} t={t} isSp={isSp} bibles={bibles} placeholder="[스마트 기능]&#13;&#10;1. 툴바를 이용해 표 생성, 정렬 가능.&#13;&#10;2. '사무엘하 21:1~4' 후 스페이스바를 누르면 본문 박스가 생성됩니다." />
              </div>
          </div>
        </div>
      </CanvasEngine>
      )}
    </div>
  );
}