import React from 'react';

export default function FamilyScreens({
  // 💡 기본 짐 & 현재 화면 상태
  activeScreen,
  t,
  isDarkMode,
  setActiveScreen,
  isSidebarOpen,
  setIsSidebarOpen,
  SubPageHeader,
  
  // 💡 가정예배 4종 세트에서 사용하는 모든 짐들
  SmileFaceIcon,
  HeartIcon,
  BibleIcon,
  PrayingHandsIcon,
  familyRoomPw,
  setFamilyRoomPw,
  renderToolbar,
  handleStickerAdd,
  handleMemoAdd,
  handleFileUpload,
  CanvasEngine,
  tool,
  setTool,
  color,
  setColor,
  size,
  setSize,
  StickerLayer,
  currDay,
  updateDay,
  onPtrDown,
  formatFamVerse,
  familyPublicData,
  setFamilyPublicData,
  getArr,
  handleAutoResize,
  triggerConfetti,
  familyRoomData,
  handleUpdateFamily
}) {

  // 🚨 [디버깅 X-ray] 필수 컴포넌트 누락 체크
  if (!SubPageHeader) return <div className="p-10 font-bold text-red-500">❌ App.js에서 SubPageHeader가 넘어오지 않았습니다!</div>;

  // 2. 화면 렌더링 (자체 switch 문으로 분기 처리)
  switch (activeScreen) {
    
    case 'familySelect':
      return (
        <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
            <SubPageHeader title="가정 예배 준비" onBack={() => setActiveScreen('fiveSetMenu')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
            <div className="flex-1 flex flex-col items-center justify-center p-6 pointer-events-auto">
                <div className="flex flex-col gap-4 md:gap-6 w-full max-w-sm">
                    <div onClick={() => setActiveScreen('familyPublic')} className={`${t.cardBg} p-6 md:p-8 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
                      {SmileFaceIcon && <SmileFaceIcon className={`w-10 h-10 md:w-12 md:h-12 ${t.purpleText} mb-3 md:mb-4`} isDark={isDarkMode} />}
                      <h3 className={`text-base md:text-lg font-black ${t.textMain}`}>공개 가정예배</h3>
                      <p className={`text-[11px] md:text-xs ${t.textSub} mt-2 text-center`}>친척 모임, 비정기 모임 등<br/>누구나 함께 참여하는 예배</p>
                    </div>
                    <div onClick={() => setActiveScreen('familyPrivateLogin')} className={`${t.cardBg} p-6 md:p-8 rounded-3xl cursor-pointer shadow-sm border ${t.border} flex flex-col items-center justify-center hover:-translate-y-1 transition-transform`}>
                      {HeartIcon && <HeartIcon className={`w-10 h-10 md:w-12 md:h-12 ${t.pinkText} mb-3 md:mb-4`} isDark={isDarkMode} />}
                      <h3 className={`text-base md:text-lg font-black ${t.textMain}`}>우리 가족 가정예배</h3>
                      <p className={`text-[11px] md:text-xs ${t.textSub} mt-2 text-center`}>오직 우리 가족만 입장 가능한<br/>프라이빗 가정 예배</p>
                    </div>
                </div>
            </div>
        </div>
      );

    case 'familyPrivateLogin':
      return (
        <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
            <SubPageHeader title="우리 가족 예배 준비" onBack={() => setActiveScreen('familySelect')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
            <div className="flex-1 flex flex-col justify-center items-center p-6 pointer-events-auto">
                <div className={`${t.cardBg} p-6 md:p-8 rounded-3xl shadow-sm border ${t.border} w-full max-w-sm flex flex-col gap-4 md:gap-5`}>
                    {HeartIcon && <HeartIcon className={`w-10 h-10 md:w-12 md:h-12 ${t.pinkText} mx-auto`} isDark={isDarkMode} />}
                    <h2 className={`text-lg md:text-xl font-bold text-center ${t.textMain}`}>우리 가족 예배방 입장</h2>
                    <input type="text" placeholder="우리 가족 고유 비밀번호..." value={familyRoomPw || ''} onChange={(e) => setFamilyRoomPw && setFamilyRoomPw(e.target.value)} className={`w-full h-10 md:h-12 px-3 md:px-4 rounded-xl text-[13px] md:text-sm font-bold border outline-none ${t.inputBg} ${t.textMain} relative z-[45] pointer-events-auto`} onPointerDown={e => e.stopPropagation()} />
                    <button onClick={() => { if(familyRoomPw) setActiveScreen('familyPrivate'); else alert("비밀번호를 입력해주세요."); }} className={`relative z-[45] pointer-events-auto w-full py-3 md:py-4 ${t.primaryBg} text-white dark:text-[#1D1D1F] font-bold rounded-xl shadow-sm hover:opacity-90 transition-colors text-[13px] md:text-sm`}>입장하기</button>
                </div>
            </div>
        </div>
      );

    case 'familyPublic': {
      const safePublicData = familyPublicData || {};
      const addFamilyPublicItem = (key, text) => setFamilyPublicData && setFamilyPublicData(p => ({ ...p, [key]: [{ id: Date.now(), text, date }, ...getArr(p[key])] }));
      const removeFamilyPublicItem = (key, id) => setFamilyPublicData && setFamilyPublicData(p => ({ ...p, [key]: getArr(p[key]).filter(item => item.id !== id) }));
      const safeFamVerse = formatFamVerse || { text: '', ref: '' };
      
      return (
        <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
            <SubPageHeader title="공개 가정 예배" onBack={() => setActiveScreen('familySelect')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
            {renderToolbar && renderToolbar(null, false, handleStickerAdd, handleMemoAdd, handleFileUpload)}
            {CanvasEngine && (
            <CanvasEngine key={`family_public`} saveKey={`family_public`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={currDay?.memos} stickers={currDay?.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} /> : null}>
                <div className="p-4 sm:p-6 flex flex-col gap-4 md:gap-6 pb-40 pointer-events-auto">
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm text-center`}>
                        <h3 className={`text-[11px] md:text-sm font-bold ${t.primaryText} mb-2 md:mb-3`}>오늘의 가정예배 말씀</h3>
                        <p className={`text-[15px] md:text-lg font-bold ${t.textMain} break-keep`}>{safeFamVerse.text}</p>
                        <p className={`text-[10px] md:text-xs ${t.textSub} mt-1.5 md:mt-2`}>{safeFamVerse.ref}</p>
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <div className="flex flex-col gap-1"><span className={`text-[10px] md:text-xs font-bold ${t.textSub}`}>👨‍👩‍👧‍👦 참석자</span><input type="text" value={safePublicData.attendees||''} onChange={(e) => setFamilyPublicData && setFamilyPublicData(p => ({...p, attendees: e.target.value}))} placeholder="예: 할아버지, 삼촌, 우리 가족..." className={`w-full h-10 md:h-12 px-3 md:px-4 rounded-xl text-[12px] md:text-sm font-bold border outline-none ${t.inputBg} ${t.textMain} relative z-[45] pointer-events-auto`} onPointerDown={e => e.stopPropagation()} /></div>
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{BibleIcon && <BibleIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.primaryText}`} isDark={isDarkMode}/>} 말씀 묵상 나누기</h3>
                       <textarea value={safePublicData.wordMeditation||''} onChange={(e) => setFamilyPublicData && setFamilyPublicData(p => ({...p, wordMeditation: e.target.value}))} onInput={handleAutoResize} placeholder="말씀을 읽고 나눈 은혜를 자유롭게 적어보세요..." className={`w-full p-3 md:p-4 rounded-xl text-[12px] md:text-sm border outline-none min-h-[80px] resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{HeartIcon && <HeartIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.pinkText}`} isDark={isDarkMode}/>} 가족 감사 나눔</h3>
                       {getArr(safePublicData.thanks).map((th) => ( 
                          <div key={th.id} className="flex gap-1.5 md:gap-2 items-start">
                             <textarea value={th.text} onChange={(e) => setFamilyPublicData && setFamilyPublicData(p => ({...p, thanks: getArr(p.thanks).map(x => x.id === th.id ? {...x, text: e.target.value} : x)}))} onInput={handleAutoResize} className={`flex-1 min-h-[40px] p-2.5 md:p-3 rounded-lg text-[12px] md:text-sm border outline-none resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                             <button onClick={() => removeFamilyPublicItem('thanks', th.id)} className={`relative z-[45] pointer-events-auto bg-[#FF2D55]/10 ${t.pinkText} h-[40px] px-2.5 md:px-3 rounded-lg text-[10px] md:text-xs font-bold shrink-0`}>삭제</button>
                          </div> 
                       ))} 
                       <button onClick={() => addFamilyPublicItem('thanks', '')} className={`relative z-[45] pointer-events-auto w-full py-2.5 md:py-3 border-2 border-dashed ${t.border} ${t.textSub} font-bold rounded-lg text-[11px] md:text-xs hover:bg-black/5 dark:hover:bg-white/5`}>+ 감사 나눔 추가</button>
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{PrayingHandsIcon && <PrayingHandsIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.yellowText}`} isDark={isDarkMode}/>} 기도 제목</h3>
                       {getArr(safePublicData.prayers).map((pr) => ( 
                          <div key={pr.id} className="flex gap-1.5 md:gap-2 items-start">
                             <textarea value={pr.text} onChange={(e) => setFamilyPublicData && setFamilyPublicData(p => ({...p, prayers: getArr(p.prayers).map(x => x.id === pr.id ? {...x, text: e.target.value} : x)}))} onInput={handleAutoResize} className={`flex-1 min-h-[40px] p-2.5 md:p-3 rounded-lg text-[12px] md:text-sm border outline-none resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                             <button onClick={() => removeFamilyPublicItem('prayers', pr.id)} className={`relative z-[45] pointer-events-auto bg-[#FF2D55]/10 ${t.pinkText} h-[40px] px-2.5 md:px-3 rounded-lg text-[10px] md:text-xs font-bold shrink-0`}>삭제</button>
                          </div> 
                       ))} 
                       <button onClick={() => addFamilyPublicItem('prayers', '')} className={`relative z-[45] pointer-events-auto w-full py-2.5 md:py-3 border-2 border-dashed ${t.border} ${t.textSub} font-bold rounded-lg text-[11px] md:text-xs hover:bg-black/5 dark:hover:bg-white/5`}>+ 기도 제목 추가</button>
                    </div>
                    
                    <button onClick={() => { updateDay && updateDay({ checks: { ...(currDay?.checks||{}), '가정예배': true } }); triggerConfetti && triggerConfetti(); alert("공개 가정예배를 완료했습니다! 🥰"); }} className={`relative z-[45] pointer-events-auto w-full py-3 md:py-4 rounded-xl font-bold text-[14px] md:text-lg shadow-sm transition-colors ${currDay?.checks?.['가정예배'] ? `${t.appBg} ${t.textSub}` : `${t.primaryBg} text-white hover:opacity-90`} ignore-draw`}>{currDay?.checks?.['가정예배'] ? '✅ 오늘 가정예배 완료됨' : '🌟 오늘 가정예배 완료 체크'}</button>
                </div>
            </CanvasEngine>
            )}
        </div>
      );
    }

    case 'familyPrivate': {
      const safeRoomData = familyRoomData || {};
      const addFamilyPrivateItem = (key, text) => handleUpdateFamily && handleUpdateFamily(p => ({ ...p, [key]: [{ id: Date.now(), text, date }, ...getArr(p[key])] }));
      const removeFamilyPrivateItem = (key, id) => handleUpdateFamily && handleUpdateFamily(p => ({ ...p, [key]: getArr(p[key]).filter(item => item.id !== id) }));
      const safeFamVerse = formatFamVerse || { text: '', ref: '' };
      
      return (
        <div className={`flex-1 flex flex-col h-full ${t.pageBg} animate-fade-in-up`}>
            <SubPageHeader title="우리가족 가정 예배" onBack={() => setActiveScreen('familySelect')} t={t} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} />
            {renderToolbar && renderToolbar(null, false, handleStickerAdd, handleMemoAdd, handleFileUpload)}
            {CanvasEngine && (
            <CanvasEngine key={`family_private`} saveKey={`family_private`} tool={tool} setTool={setTool} color={color} setColor={setColor} size={size} setSize={setSize} t={t} renderStickers={() => StickerLayer ? <StickerLayer memos={currDay?.memos} stickers={currDay?.stickers} onUpdateMemos={(m)=>updateDay({memos:m})} onUpdateStickers={(s)=>updateDay({stickers:s})} onPtrDown={onPtrDown} /> : null}>
                <div className="p-4 sm:p-6 flex flex-col gap-4 md:gap-6 pb-40 pointer-events-auto">
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm text-center`}><h3 className={`text-[11px] md:text-sm font-bold ${t.pinkText} mb-2 md:mb-3`}>오늘의 가정예배 말씀</h3><p className={`text-[15px] md:text-lg font-bold ${t.textMain} break-keep`}>{safeFamVerse.text}</p><p className={`text-[10px] md:text-xs ${t.textSub} mt-1.5 md:mt-2`}>{safeFamVerse.ref}</p></div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <div className="flex flex-col gap-1"><span className={`text-[10px] md:text-xs font-bold ${t.textSub}`}>👨‍👩‍👧‍👦 참석자</span><input type="text" value={safeRoomData.attendees||''} onChange={(e) => handleUpdateFamily && handleUpdateFamily(p => ({...p, attendees: e.target.value}))} placeholder="예: 아빠, 엄마, 은우" className={`w-full h-10 md:h-12 px-3 md:px-4 rounded-xl text-[12px] md:text-sm font-bold border outline-none ${t.inputBg} ${t.textMain} relative z-[45] pointer-events-auto`} onPointerDown={e => e.stopPropagation()} /></div>
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{BibleIcon && <BibleIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.primaryText}`} isDark={isDarkMode}/>} 말씀 묵상 나누기</h3>
                       <textarea value={safeRoomData.wordMeditation||''} onChange={(e) => handleUpdateFamily && handleUpdateFamily(p => ({...p, wordMeditation: e.target.value}))} onInput={handleAutoResize} placeholder="말씀을 읽고 나눈 은혜를 자유롭게 적어보세요..." className={`w-full p-3 md:p-4 rounded-xl text-[12px] md:text-sm border outline-none min-h-[80px] resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{HeartIcon && <HeartIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.pinkText}`} isDark={isDarkMode}/>} 가족 감사 나눔</h3>
                       {getArr(safeRoomData.thanks).map((th) => ( 
                          <div key={th.id} className="flex gap-1.5 md:gap-2 items-start">
                             <textarea value={th.text} onChange={(e) => handleUpdateFamily && handleUpdateFamily(p => ({...p, thanks: getArr(p.thanks).map(x => x.id === th.id ? {...x, text: e.target.value} : x)}))} onInput={handleAutoResize} className={`flex-1 min-h-[40px] p-2.5 md:p-3 rounded-lg text-[12px] md:text-sm border outline-none resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                             <button onClick={() => removeFamilyPrivateItem('thanks', th.id)} className={`relative z-[45] pointer-events-auto bg-[#FF2D55]/10 ${t.pinkText} h-[40px] px-2.5 md:px-3 rounded-lg text-[10px] md:text-xs font-bold shrink-0`}>삭제</button>
                          </div> 
                       ))} 
                       <button onClick={() => addFamilyPrivateItem('thanks', '')} className={`relative z-[45] pointer-events-auto w-full py-2.5 md:py-3 border-2 border-dashed ${t.border} ${t.textSub} font-bold rounded-lg text-[11px] md:text-xs hover:bg-black/5 dark:hover:bg-white/5`}>+ 감사 나눔 추가</button>
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{PrayingHandsIcon && <PrayingHandsIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.greenText}`} isDark={isDarkMode}/>} 가족 기도 제목</h3>
                       {getArr(safeRoomData.prayers).map((pr) => ( 
                          <div key={pr.id} className="flex gap-1.5 md:gap-2 items-start">
                             <textarea value={pr.text} onChange={(e) => handleUpdateFamily && handleUpdateFamily(p => ({...p, prayers: getArr(p.prayers).map(x => x.id === pr.id ? {...x, text: e.target.value} : x)}))} onInput={handleAutoResize} className={`flex-1 min-h-[40px] p-2.5 md:p-3 rounded-lg text-[12px] md:text-sm border outline-none resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                             <button onClick={() => removeFamilyPrivateItem('prayers', pr.id)} className={`relative z-[45] pointer-events-auto bg-[#FF2D55]/10 ${t.pinkText} h-[40px] px-2.5 md:px-3 rounded-lg text-[10px] md:text-xs font-bold shrink-0`}>삭제</button>
                          </div> 
                       ))} 
                       <button onClick={() => addFamilyPrivateItem('prayers', '')} className={`relative z-[45] pointer-events-auto w-full py-2.5 md:py-3 border-2 border-dashed ${t.border} ${t.textSub} font-bold rounded-lg text-[11px] md:text-xs hover:bg-black/5 dark:hover:bg-white/5`}>+ 기도 제목 추가</button>
                    </div>
                    
                    <div className={`${t.cardBg} p-4 md:p-5 rounded-2xl border ${t.border} shadow-sm flex flex-col gap-3 md:gap-4`}>
                       <h3 className={`font-bold ${t.textMain} text-[12px] md:text-sm flex items-center gap-2`}>{SmileFaceIcon && <SmileFaceIcon className={`w-4 h-4 md:w-5 md:h-5 ${t.purpleText}`} isDark={isDarkMode}/>} 우리 가족 칭찬하기</h3>
                       {getArr(safeRoomData.goodDeeds).map((gd) => ( 
                          <div key={gd.id} className="flex gap-1.5 md:gap-2 items-start">
                             <textarea value={gd.text} onChange={(e) => handleUpdateFamily && handleUpdateFamily(p => ({...p, goodDeeds: getArr(p.goodDeeds).map(x => x.id === gd.id ? {...x, text: e.target.value} : x)}))} onInput={handleAutoResize} placeholder="누구를, 어떤 일로 칭찬하나요?" className={`flex-1 min-h-[40px] p-2.5 md:p-3 rounded-lg text-[12px] md:text-sm border outline-none resize-none overflow-hidden ${t.inputBg} ${t.textMain} whitespace-pre-wrap relative z-[45] pointer-events-auto`} onPointerDown={e=>e.stopPropagation()} />
                             <button onClick={() => removeFamilyPrivateItem('goodDeeds', gd.id)} className={`relative z-[45] pointer-events-auto bg-[#FF2D55]/10 ${t.pinkText} h-[40px] px-2.5 md:px-3 rounded-lg text-[10px] md:text-xs font-bold shrink-0`}>삭제</button>
                          </div> 
                       ))} 
                       <button onClick={() => addFamilyPrivateItem('goodDeeds', '')} className={`relative z-[45] pointer-events-auto w-full py-2.5 md:py-3 border-2 border-dashed ${t.border} ${t.textSub} font-bold rounded-lg text-[11px] md:text-xs hover:bg-black/5 dark:hover:bg-white/5`}>+ 칭찬 추가하기</button>
                    </div>
                    
                    <button onClick={() => { updateDay && updateDay({ checks: { ...(currDay?.checks||{}), '가정예배': true } }); triggerConfetti && triggerConfetti(); alert("가정예배를 완료했습니다! 🥰"); }} className={`relative z-[45] pointer-events-auto w-full py-3 md:py-4 rounded-xl font-bold text-[14px] md:text-lg shadow-sm transition-colors ${currDay?.checks?.['가정예배'] ? `${t.appBg} ${t.textSub}` : `bg-pink-500 text-white hover:opacity-90`}`}>{currDay?.checks?.['가정예배'] ? '✅ 오늘 가정예배 완료됨' : '🌟 오늘 가정예배 완료 체크'}</button>
                </div>
            </CanvasEngine>
            )}
        </div>
      );
    }

    default:
      return null;
  }
}